// _T removed — use useTheme() inside components, or pass T as prop to pure helpers.
// Module-level style helpers (glass, homeGlass, inlineBg, navGlass) now accept T
// explicitly so they remain pure functions with no hidden global state.
let _T = THEMES[0]; // legacy shim — updated via ThemeContext; kept for gradual migration

// ===== 表情立绘 base64（主题选择器图标）=====
// 亮色主题用线稿，暗色主题用彩色（对比度更佳）
