// inlineBg — returns a valid CSS color string.
// BUG FIX: previous active branch appended a float opacity to a hex color string
// e.g. "#C48AA4" + "0.15)" → "#C48AA40.15)" which is invalid CSS.
// Now converts opacity to a two-digit hex alpha and appends correctly.
const inlineBg = (op = 0.3, active = false) => {
  if (active && _T.cardActive) {
    // Convert fractional opacity (0–1) to two-hex-digit alpha channel
    const alpha = Math.round(Math.min(1, Math.max(0, op)) * 255)
      .toString(16)
      .padStart(2, "0");
    return `${_T.cardActive}${alpha}`;
  }
  return `${_T.glassBg}${_T.dark ? op * (_T.darkOpMul ?? 0.15) : op * 0.55})`;
};
// ═══════════════════════════════════════════════════════════════════════════════
// iOS 26 液态玻璃材质系统
// 核心特征：深层模糊 + 棱镜折射高光 + 流体边缘 + 动态光晕 + 多层内阴影
// ═══════════════════════════════════════════════════════════════════════════════

// Android WebView 不支持 backdropFilter，需要用更不透明的实色背景代替玻璃效果
const isAndroid = /Android/i.test(navigator.userAgent);

const glass = (op = 0.35, blur = 28) => {
  // 暗色主题用深色 glassCardBg，亮色主题用 wall 同色系底色，不再是纯白
  // Android 上提高不透明度，让主题色充分显示（不依赖 backdropFilter）
  const bgOpacity = _T.dark ? op * 0.72 : (isAndroid ? Math.min(op * 2.2, 0.92) : op * 1.6);
  const bg = _T.glassCardBg
    ? `${_T.glassCardBg}${bgOpacity})`
    : `${_T.glassBg}${op * 0.48})`;

  // ── 棱镜内高光：顶边锐线 + 内侧柔晕，模拟玻璃折射厚度 ──────────────
  const specTop = _T.dark
    ? `inset 0 1.5px 0 rgba(255,255,255,0.17), inset 0 4px 12px rgba(255,255,255,0.04)`
    : `inset 0 1.5px 0 rgba(255,255,255,0.92), inset 0 5px 14px rgba(255,255,255,0.30)`;
  const specLeft = _T.dark
    ? `inset 1.5px 0 0 rgba(255,255,255,0.07)`
    : `inset 1.5px 0 0 rgba(255,255,255,0.58), inset 5px 0 14px rgba(255,255,255,0.10)`;
  const specBottom = _T.dark
    ? `inset 0 -1.5px 0 rgba(0,0,0,0.42), inset 0 -6px 16px rgba(0,0,0,0.22)`
    : `inset 0 -1px 0 rgba(0,0,0,0.06), inset 0 -4px 10px rgba(0,0,0,0.04)`;

  // ── 三层外投影：接触锐边 → 中距漫射 → 彩色远端光晕 ──────────────────
  const sh0 = `0 1px 4px rgba(0,0,0,${_T.dark ? 0.34 : 0.08})`;
  const sh1 = `0 7px 22px ${_T.glassSH}`;
  const sh2 = _T.cardGlow
    ? `0 20px 52px ${_T.cardGlow}26`
    : `0 20px 52px rgba(0,0,0,${_T.dark ? 0.16 : 0.05})`;

  // ── 折射背景层 ─────────────────────────────────────────────────────────
  const refractGrad = !_T.dark
    ? isAndroid
      ? `linear-gradient(135deg, ${_T.primary}22 0%, ${_T.primary}0C 100%)`
      : `linear-gradient(152deg, rgba(255,255,255,0.44) 0%, ${_T.primary}07 50%, rgba(255,255,255,0.14) 100%)`
    : `linear-gradient(142deg, ${_T.primary}1E 0%, rgba(255,255,255,0.03) 48%, ${_T.accent2 || _T.primary}12 100%)`;

  return {
    background: `${refractGrad}, ${bg}`,
    backdropFilter: isAndroid ? 'none' : `blur(${blur}px) saturate(${_T.dark ? 1.55 : 1.85}) brightness(${_T.dark ? 1.07 : 1.01})`,
    WebkitBackdropFilter: isAndroid ? 'none' : `blur(${blur}px) saturate(${_T.dark ? 1.55 : 1.85}) brightness(${_T.dark ? 1.07 : 1.01})`,
    border: `1px solid ${_T.glassBorder}`,
    boxShadow: `${sh2}, ${sh1}, ${sh0}, ${specTop}, ${specLeft}, ${specBottom}`,
  };
};

// ===== 主页卡片专用 glass — 流体玻璃景深升级版 =====
const homeGlass = (op = 0.42, blur = 32) => {
  const base = glass(op, blur);

  // 直接计算 bg，避免用 split 解析复合渐变（更安全）
  const bgOpacity = _T.dark ? op * 0.72 : (isAndroid ? Math.min(op * 2.2, 0.92) : op * 1.6);
  const bg = _T.glassCardBg
    ? `${_T.glassCardBg}${bgOpacity})`
    : `${_T.glassBg}${op * 0.48})`;

  // ── 球面镜头光层：模拟光线从卡片正上方穿透玻璃 ────────────────────────
  // 亮色：顶中央强椭圆白高光 + 侧边主题色晕染
  // 暗色：双极光（主色 + accent）+ 微白顶高光
  // Android亮色：主题色替代白色
  const lensLayer = _T.dark
    ? `radial-gradient(ellipse at 36% -10%, ${_T.primary}32 0%, transparent 58%),
       radial-gradient(ellipse at 80% 110%, ${_T.accent2 || _T.primary}1C 0%, transparent 52%),
       linear-gradient(158deg, rgba(255,255,255,0.09) 0%, transparent 42%)`
    : isAndroid
      ? `radial-gradient(ellipse at 28% -10%, ${_T.primary}32 0%, transparent 54%),
         linear-gradient(148deg, ${_T.primary}1E 0%, ${_T.primary}09 65%)`
      : `radial-gradient(ellipse at 50% -14%, rgba(255,255,255,0.75) 0%, transparent 50%),
         radial-gradient(ellipse at 16% 58%, ${_T.primary}1A 0%, transparent 54%),
         linear-gradient(154deg, rgba(255,255,255,0.28) 0%, ${_T.primary}07 52%, rgba(255,255,255,0.08) 100%)`;

  // ── 四面内凹阴影：强化玻璃厚度与悬浮感 ───────────────────────────────
  const lens = _T.dark
    ? `inset 0 4px 16px rgba(0,0,0,0.40), inset 0 -3px 10px rgba(0,0,0,0.22), inset 3px 0 12px rgba(0,0,0,0.14), inset -2px 0 8px rgba(0,0,0,0.10)`
    : `inset 0 4px 14px ${_T.primary}13, inset 0 -2px 8px ${_T.primary}08, inset 3px 0 12px ${_T.primary}08, inset -2px 0 6px ${_T.primary}05`;

  // ── 三层外光晕：近端锐边 → 中距主题色 → 远端漫射 ─────────────────────
  const glow = _T.dark
    ? `0 2px 8px rgba(0,0,0,0.36), 0 16px 44px ${_T.primary}22, 0 36px 80px ${_T.primary}0E`
    : `0 2px 10px rgba(0,0,0,0.09), 0 16px 44px ${_T.primary}1C, 0 40px 80px ${_T.primary}0C`;

  return {
    ...base,
    background: `${lensLayer}, ${bg}`,
    boxShadow: `${glow}, ${base.boxShadow}, ${lens}`,
    transition: 'box-shadow 0.25s cubic-bezier(0.4,0,0.2,1), background 0.25s cubic-bezier(0.4,0,0.2,1)',
  };
};

// 导航栏专用 glass：同材质更深、无外边框外投影，与页面内容连为一体
// navGlass 接收当前 theme T，用 wall 色系匹配壁纸底部，不用 backdropFilter
// （overflow:hidden 容器内 backdropFilter 会产生硬裁切线，必须去掉）
const navGlass = (T) => ({
  // 用 wall[3]/wall[4] 混合：与渐变遮罩底色完全一致，零色差
  // bottom 必须 FF（完全不透明），防止底部圆角区域透出外层背景产生白边
  background: T.dark
    ? `linear-gradient(to bottom, ${T.wall[2]}E0, ${T.wall[3]}FF)`
    : `linear-gradient(to bottom, ${T.wall[3]}D8, ${T.wall[4]}FF)`,
  backdropFilter: 'none',
  WebkitBackdropFilter: 'none',
  boxShadow: 'none',
  border: 'none',
});

