// PixelIcon — wrapped in memo; rects array is also memoized inside.
// Previously re-created up to 196 SVG <rect> elements on every parent render.
const PixelIcon = memo(function PixelIcon({ id, color, size = 14 }) {
  const rows = PIX[id] || PIX.home;
  const G = 14;
  const dark   = color + "BB";
  const light  = "rgba(255,255,255,0.82)";
  const accent = "#E86070";
  // Memoize the rect array — only recomputes when id or color changes
  const rects = useMemo(() =>
    rows.flatMap((row, y) =>
      row.split("").map((cell, x) => {
        if (cell === "0") return null;
        const fill = cell === "2" ? dark
                   : cell === "3" ? light
                   : cell === "4" ? accent
                   : color;
        return <rect key={`${x}-${y}`} x={x} y={y} width={1} height={1} fill={fill} />;
      })
    ),
    [rows, color, dark] // eslint-disable-line react-hooks/exhaustive-deps
  );
  return (
    <svg
      width={size} height={size}
      viewBox={`0 0 ${G} ${G}`}
      style={{ imageRendering: "pixelated", display: "block", flexShrink: 0, overflow: "visible" }}
    >
      {rects}
    </svg>
  );
});

