// Convert hex color to a lightened highlight color
function lightenHex(hex, amount = 0.5) {
  const h = hex.replace('#','');
  const r = parseInt(h.slice(0,2),16);
  const g = parseInt(h.slice(2,4),16);
  const b = parseInt(h.slice(4,6),16);
  const lr = Math.round(r + (255-r)*amount);
  const lg = Math.round(g + (255-g)*amount);
  const lb = Math.round(b + (255-b)*amount);
  return `rgb(${lr},${lg},${lb})`;
}

// Residue — fully rewritten with jirai-kei pixel SVG icons
// API is 100% backward-compatible: same props, same call sites.
const Residue = memo(function Residue({ glyph = "·", size = 1, color, style: extra = {}, pulse = true, drift = true }) {
  const theme = useTheme();
  const c = color || theme.primary;
  const safeBase = typeof c === "string" && c.startsWith("#") ? c : (theme.primaryLight || "#ffffff");
  const hl = lightenHex(safeBase, 0.55);
  const seed = (glyph.charCodeAt(0) * 7 + Math.round(size * 13)) % 100;
  const dur1 = 3.2 + (seed % 40) * 0.06;
  const delay = (seed % 50) * 0.04;
  const px = Math.round(13 * size);
  const box = px + 4;
  const iconPaths = JIRAI_SVG[glyph] || JIRAI_SVG["·"];

  const animStyle = pulse || drift ? {
    animation: `residueBreathe ${dur1}s ease-in-out ${delay}s infinite`,
    transformOrigin: "center center",
  } : {};

  return (
    <span style={{
      position: "relative",
      display: "inline-flex",
      alignItems: "center",
      justifyContent: "center",
      verticalAlign: "middle",
      alignSelf: "center",
      textAlign: "center",
      lineHeight: 0,
      width: box,
      minWidth: box,
      height: box,
      minHeight: box,
      flexShrink: 0,
      overflow: "visible",
      transform: "translateZ(0)",
      ...extra,
    }}>
      <span style={{
        position: "absolute",
        inset: 0,
        borderRadius: "50%",
        background: `radial-gradient(circle, ${c}22 0%, ${c}08 55%, transparent 80%)`,
        pointerEvents: "none",
        animation: pulse ? `residueBreathe ${dur1}s ease-in-out ${delay}s infinite` : "none",
      }} />
      <svg
        width={px}
        height={px}
        viewBox="0 0 16 16"
        xmlns="http://www.w3.org/2000/svg"
        style={{
          display: "block",
          position: "relative",
          zIndex: 1,
          flexShrink: 0,
          overflow: "visible",
          filter: `drop-shadow(0 0 ${Math.round(2 * size)}px ${c}55)`,
          ...animStyle,
        }}
      >
        {iconPaths(c, hl)}
      </svg>
    </span>
  );
});


// CardResidue — 升级版：3个装饰元素，分层动效（漂浮+呼吸+自转+轨道）
const CARD_RESIDUE_GLYPHS = ["·", "○", "—", "·", "✕"];
const CardResidue = memo(function CardResidue({ color, seed = 0 }) {
  const theme = useTheme();
  const c = color || theme.primary;
  const c2 = theme.accent2 || theme.primary;
  const c3 = theme.primaryDeep || theme.primary;
  const hl  = lightenHex(c.startsWith('#')  ? c  : '#e8a0b4', 0.55);
  const hl2 = lightenHex(c2.startsWith('#') ? c2 : '#b0c8d8', 0.55);
  const hl3 = lightenHex(c3.startsWith('#') ? c3 : '#d4a0c0', 0.55);

  // 三个装饰元素，位置/尺寸/延迟全部由 seed 决定
  const g1 = CARD_RESIDUE_GLYPHS[seed % CARD_RESIDUE_GLYPHS.length];
  const g2 = CARD_RESIDUE_GLYPHS[(seed + 2) % CARD_RESIDUE_GLYPHS.length];
  const g3 = CARD_RESIDUE_GLYPHS[(seed + 4) % CARD_RESIDUE_GLYPHS.length];
  const p1 = JIRAI_SVG[g1] || JIRAI_SVG["·"];
  const p2 = JIRAI_SVG[g2] || JIRAI_SVG["·"];
  const p3 = JIRAI_SVG[g3] || JIRAI_SVG["·"];

  // 位置 — 右上 / 左下 / 右下三角分布
  const x1 = 62 + (seed % 22);  const y1 = 10 + (seed % 28);
  const x2 = 5  + (seed % 18);  const y2 = 55 + (seed % 28);
  const x3 = 42 + (seed % 20);  const y3 = 60 + (seed % 22);

  const sz1 = 13 + (seed % 5);
  const sz2 = 9  + (seed % 4);
  const sz3 = 7  + (seed % 3);

  const rot1 = (seed % 40) - 20;
  const rot2 = (seed % 30) - 15;
  const rot3 = (seed % 50) - 25;

  // 动画时长 — 三个元素用不同节奏，避免同步
  const dur1 = 3.4 + (seed % 18) * 0.14;   // 漂浮
  const dur2 = 5.6 + (seed % 14) * 0.18;   // 呼吸
  const dur3 = 7.2 + (seed % 10) * 0.22;   // 轨道漂移
  const del1 = (seed % 12) * 0.16;
  const del2 = 0.5 + (seed % 9) * 0.22;
  const del3 = 1.2 + (seed % 7) * 0.3;

  return (
    <>
      {/* 元素1 — 右上：漂浮 + 自转 + 强呼吸 */}
      <span style={{
        position: "absolute", right: `${x1}%`, top: `${y1}%`,
        width: sz1, height: sz1,
        opacity: 0,
        pointerEvents: "none", zIndex: 0,
        animation: [
          `cardDecoIn 0.6s cubic-bezier(.175,.885,.32,1.275) ${del1 + 0.1}s forwards`,
          `cardDecoFloat ${dur1}s ease-in-out ${del1}s infinite`,
          `cardDecoSpin ${dur1 * 4.5}s linear ${del1}s infinite`,
        ].join(", "),
        transformOrigin: "center center",
        filter: `drop-shadow(0 0 3px ${c}30) drop-shadow(0 0 1px ${c}18)`,
      }}>
        <svg width={sz1} height={sz1} viewBox="0 0 16 16" xmlns="http://www.w3.org/2000/svg"
          style={{ transform: `rotate(${rot1}deg)` }}>
          {p1(c, hl)}
        </svg>
      </span>

      {/* 元素2 — 左下：轨道漂移 + 柔和呼吸 */}
      <span style={{
        position: "absolute", left: `${x2}%`, bottom: `${y2}%`,
        width: sz2, height: sz2,
        opacity: 0,
        pointerEvents: "none", zIndex: 0,
        animation: [
          `cardDecoIn 0.55s cubic-bezier(.175,.885,.32,1.275) ${del2 + 0.2}s forwards`,
          `cardDecoOrbit ${dur2}s ease-in-out ${del2}s infinite`,
          `cardDecoPulse ${dur2 * 0.7}s ease-in-out ${del2}s infinite`,
        ].join(", "),
        transformOrigin: "center center",
        filter: `drop-shadow(0 0 2px ${c2}28)`,
      }}>
        <svg width={sz2} height={sz2} viewBox="0 0 16 16" xmlns="http://www.w3.org/2000/svg"
          style={{ transform: `rotate(${rot2}deg)` }}>
          {p2(c2, hl2)}
        </svg>
      </span>

      {/* 元素3 — 右下角：慢速漂浮 + 光晕闪烁 */}
      <span style={{
        position: "absolute", right: `${x3}%`, bottom: `${y3 - 30}%`,
        width: sz3, height: sz3,
        opacity: 0,
        pointerEvents: "none", zIndex: 0,
        animation: [
          `cardDecoIn 0.5s ease-out ${del3 + 0.3}s forwards`,
          `cardDecoGlimmer ${dur3}s ease-in-out ${del3}s infinite`,
        ].join(", "),
        filter: `drop-shadow(0 0 2px ${c3}38)`,
      }}>
        <svg width={sz3} height={sz3} viewBox="0 0 16 16" xmlns="http://www.w3.org/2000/svg"
          style={{ transform: `rotate(${rot3}deg)` }}>
          {p3(c3, hl3)}
        </svg>
      </span>
    </>
  );
});

