            {/* 高光 */}
            <ellipse cx="5" cy="4" rx="1.8" ry="1.1" fill="white" fillOpacity="0.28" transform="rotate(-20 5 4)"/>
            {/* 中脉 */}
            <path d="M7,2 Q6.5,6 6.8,11" stroke="white" strokeWidth="0.35" strokeOpacity="0.3" fill="none" strokeLinecap="round"/>
