// 觉醒维度 专属地雷系图标 — 16×16 viewBox，内联 SVG
function AdvIcon({ iconKey, color, size = 16 }) {
  const c = color;
  // lighten for highlight
  const hl = "rgba(255,255,255,0.7)";
  if (iconKey === "stability") {
    // 四角星 sparkle — 稳定性（向心力，收敛）
    return (
      <svg width={size} height={size} viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
        <path d="M8,1 C8,1 6.8,6.2 1,8 C6.8,9.8 8,15 8,15 C8,15 9.2,9.8 15,8 C9.2,6.2 8,1 8,1Z" fill={c} fillOpacity="0.92"/>
        <path d="M8,1 C8,1 7.2,5 4,6.5 C6.5,5.8 8,1 8,1Z" fill={hl} fillOpacity="0.42"/>
        <circle cx="8" cy="8" r="1.4" fill={hl} fillOpacity="0.75"/>
        <circle cx="8" cy="8" r="6.5" fill="none" stroke={c} strokeWidth="0.5" strokeOpacity="0.3"/>
      </svg>
    );
  }
  if (iconKey === "sync") {
    // 双心 connected hearts — 同步感（联结，共振）
    return (
      <svg width={size} height={size} viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
        {/* left heart */}
        <path d="M4.5,5 C4.5,5 2,5 2,7.5 C2,10 4.5,12 7,13.5 C7,13.5 5,10 5,7.5 C5,6 5.5,5 4.5,5Z" fill={c} fillOpacity="0.75"/>
        <path d="M4.5,5 C4.5,5 7,5 7,7.5 C7,10 4.5,12 7,13.5" fill={c} fillOpacity="0.85"/>
        <path d="M3,5.5 C2.5,6.2 2,7 2.2,8" stroke={hl} strokeWidth="0.6" strokeOpacity="0.55" fill="none" strokeLinecap="round"/>
        {/* connecting link */}
        <line x1="7" y1="9.5" x2="9" y2="9.5" stroke={c} strokeWidth="0.7" strokeOpacity="0.5"/>
        {/* right heart */}
        <path d="M11.5,5 C11.5,5 14,5 14,7.5 C14,10 11.5,12 9,13.5 C9,13.5 11,10 11,7.5 C11,6 10.5,5 11.5,5Z" fill={c} fillOpacity="0.75"/>
        <path d="M11.5,5 C11.5,5 9,5 9,7.5 C9,10 11.5,12 9,13.5" fill={c} fillOpacity="0.85"/>
        <path d="M13,5.5 C13.5,6.2 14,7 13.8,8" stroke={hl} strokeWidth="0.6" strokeOpacity="0.45" fill="none" strokeLinecap="round"/>
      </svg>
    );
  }
  // bodyCommit — 蝴蝶结 bow，身体投入 = 自我表达
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
      {/* left wing */}
      <path d="M8,8 C7,5 4,2.5 1,4 C-0.5,6.5 1.5,10 8,8.8Z" fill={c} fillOpacity="0.88"/>
      <path d="M8,8 C7.5,6 5.5,4 3.5,4.5 C5.5,4 7.5,6 7.5,8Z" fill={hl} fillOpacity="0.32"/>
      {/* right wing */}
      <path d="M8,8 C9,5 12,2.5 15,4 C16.5,6.5 14.5,10 8,8.8Z" fill={c} fillOpacity="0.85"/>
      <path d="M8,8 C8.5,6 10.5,4 12.5,4.5 C10.5,4 8.5,6 8.5,8Z" fill={hl} fillOpacity="0.28"/>
      {/* left tail */}
      <path d="M7,9.2 C6,11.5 5.5,14 7,15 C7.8,15.5 8,14 7.5,9.5Z" fill={c} fillOpacity="0.72"/>
      {/* right tail */}
      <path d="M9,9.2 C10,11.5 10.5,14 9,15 C8.2,15.5 8,14 8.5,9.5Z" fill={c} fillOpacity="0.70"/>
      {/* center knot */}
      <rect x="6" y="6.2" width="4" height="4" rx="1.4" fill={c}/>
      <rect x="6" y="6.2" width="4" height="1.5" rx="1.4" fill={hl} fillOpacity="0.45"/>
      <ellipse cx="7" cy="7.2" rx="0.9" ry="0.6" fill={hl} fillOpacity="0.5"/>
    </svg>
  );
}

