// ─── Persistence helpers ────────────────────────────────────────────────────
// BUG FIX: previous implementation only wrote to an in-memory _memStore object.
// That means every page refresh wiped all practice sessions, live data, songs, etc.
// Now we use localStorage as primary storage with _memStore as an in-tab fallback
// (covers environments where localStorage is unavailable, e.g. some sandboxes).
const _memStore = {};
function safeLoad(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    if (raw !== null) return JSON.parse(raw);
  } catch { /* localStorage unavailable or JSON malformed */ }
  return _memStore[key] !== undefined ? _memStore[key] : fallback;
}
function safeSave(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch { /* quota exceeded or storage unavailable */ }
  _memStore[key] = value;
}
function formatDuration(seconds = 0) {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
}
function getSongStatusLabel(status) {
  if (status === "smooth") return "— 稳定";
  if (status === "almost") return "— 未完成";
  return "— 未开始";
}
function getSongStatusColor(status) {
  if (status === "smooth") return _T.statusOk  || "#6A9A7A";
  if (status === "almost") return _T.statusBad || _T.primary;
  return _T.statusGray || _T.textLight;
}
function getSongStatusGlow(status) {
  if (status === "smooth") return _T.statusOkGlow ? `0 0 6px ${_T.statusOkGlow}` : "none";
  if (status === "almost") return _T.dotGlow || "none";
  return "none";
}
function pickTodayFocus(songs, nextLive) {
  const liveSongs = nextLive.setlist.map(i => i.song).filter(Boolean);
  const liveRelevantSongs = songs.filter(song => liveSongs.includes(song.title));
  const almost = liveRelevantSongs.find(song => song.status === "almost") || songs.find(song => song.status === "almost");
  if (almost) {
    return {
      title: almost.title,
      text: `「${almost.title}」— 未完成`,
      sub: almost.note
    };
  }
  const newer = liveRelevantSongs.find(song => song.status === "new") || songs.find(song => song.status === "new");
  if (newer) {
    return {
      title: newer.title,
      text: `「${newer.title}」— 待处理`,
      sub: newer.note
    };
  }
  const fallback = liveRelevantSongs[0] || songs[0];
  return {
    title: fallback.title,
    text: `「${fallback.title}」`,
    sub: fallback.note
  };
}
function computeLiveReadiness(songs, nextLive) {
  const liveSongs = nextLive.setlist.map(i => i.song).filter(Boolean);
  const matched = songs.filter(song => liveSongs.includes(song.title));
  const smoothCount = matched.filter(song => song.status === "smooth").length;
  const almostCount = matched.filter(song => song.status === "almost").length;
  if (smoothCount === matched.length && matched.length) return "— 趋于稳定";
  if (almostCount >= 1) return "— 有残留未完成项";
  return "— 进行中";
}
function buildRecentChanges(songs, sessions, liveReviews) {
  const changes = [];
  const bestSong = [...songs].sort((a, b) => (b.passCount || 0) - (a.passCount || 0))[0];
  if (bestSong) changes.push(`「${bestSong.title}」— 有变化`);
  if (sessions.length >= 3) changes.push("连续练习 — 已记录");
  const tiredReview = liveReviews.find(r => r.feeling === "tired");
  if (tiredReview) changes.push("上一场 — 疲倦标记");
  if (changes.length === 0) changes.push("— 无新变化");
  return changes.slice(0, 3);
}
function deriveMilestones(songs, sessions, liveReviews) {
  const items = [];
  const stableSong = songs.find(song => song.status === "smooth");
  if (stableSong) {
    items.push({ icon: "○", label: `「${stableSong.title}」— 稳定`, date: "最近", action: "practice_song", songId: stableSong.id, hint: "开始练习 →" });
  }
  if (sessions.length >= 7) {
    items.push({ icon: "·", label: "连续7日 — 已标记", date: "已达成", action: "spectrum", hint: "查看光谱 →" });
  }
  if (liveReviews.length) {
    items.push({ icon: "…", label: "上一场 — 存档", date: "刚刚", action: "reflection", hint: "查看复盘 →" });
  }
  if (!items.length) items.push({ icon: "—", label: "进行中", date: "现在", action: "practice", hint: "去练习 →" });
  return items.slice(0, 3);
}
function deriveStability(sessions, songs) {
  const songSessions = {};
  sessions.forEach(s => {
    if (!songSessions[s.songId]) songSessions[s.songId] = [];
    songSessions[s.songId].push(s.passes / Math.max(1, s.passes + s.retries));
  });
  const ratios = Object.values(songSessions).filter(arr => arr.length >= 2);
  if (!ratios.length) return 1;
  const avgVariance = ratios.reduce((acc, arr) => {
    const mean = arr.reduce((a, b) => a + b, 0) / arr.length;
    const variance = arr.reduce((a, v) => a + Math.abs(v - mean), 0) / arr.length;
    return acc + (1 - variance);
  }, 0) / ratios.length;
  return Math.min(4, Math.max(1, Math.round(avgVariance * 4)));
}
function deriveSync(sessions, liveReviews) {
  const smoothLives = liveReviews.filter(r => r.feeling === "smooth").length;
  const totalLives = liveReviews.length;
  const uniqueSongs = new Set(sessions.map(s => s.songId)).size;
  const base = totalLives > 0 ? (smoothLives / totalLives) * 3 : 1;
  const bonus = uniqueSongs >= 3 ? 1 : 0;
  return Math.min(4, Math.max(1, Math.round(base + bonus)));
}
function deriveBodyCommit(sessions, songs, liveReviews) {
  const totalDuration = sessions.reduce((acc, item) => acc + (item.duration || 0), 0);
  const totalPass = songs.reduce((acc, item) => acc + (item.passCount || 0), 0);
  const tiredRatio = liveReviews.length ? liveReviews.filter(r => r.feeling === "tired").length / liveReviews.length : 0.5;
  const durationScore = totalDuration > 1800 ? 2 : totalDuration > 600 ? 1 : 0;
  const passScore = totalPass > 8 ? 2 : totalPass > 3 ? 1 : 0;
  const energyScore = tiredRatio < 0.4 ? 1 : 0;
  return Math.min(4, Math.max(1, durationScore + passScore + energyScore));
}
function deriveAbilities(sessions, songs, liveReviews) {
  const totalDuration = sessions.reduce((acc, item) => acc + (item.duration || 0), 0);
  const totalPass = songs.reduce((acc, item) => acc + (item.passCount || 0), 0);
  const totalRetry = songs.reduce((acc, item) => acc + (item.retryCount || 0), 0);
  const recentTired = liveReviews.some(item => item.feeling === "tired");

  const voice = Math.min(4, Math.max(1, Math.round(totalPass / 3)));
  const motion = Math.min(4, Math.max(1, Math.round((totalPass - totalRetry * 0.25) / 3)));
  const stage = recentTired ? 2 : Math.min(4, Math.max(2, Math.round((liveReviews.length + 2) / 2)));
  const song = Math.min(4, Math.max(1, songs.filter(item => item.status !== "new").length));
  const stamina = totalDuration > 1200 ? 3 : 2;

  return {
    voice, motion, stage, song, stamina,
    stability: deriveStability(sessions, songs),
    sync: deriveSync(sessions, liveReviews),
    bodyCommit: deriveBodyCommit(sessions, songs, liveReviews)
  };
}
function softAbilityText(level) {
  if (level <= 1) return "…";
  if (level === 2) return "—";
  if (level === 3) return "○";
  return "·";
}
function createPracticeSummary(song, retries, passes, duration) {
  if (passes >= 2) return `「${song?.title}」— 有推进。已记录。`;
  if (retries >= 3) return `「${song?.title}」— 触碰到难点。`;
  if (duration >= 600) return `时长已记录。`;
  return `第一次。已标记。`;
}
function buildSessionEvent(type, payload = {}) {
  return { id: `${type}_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`, type, at: Date.now(), ...payload };
}
// BUG FIX: was always returning the hardcoded string "刚刚".
// Now accepts an optional timestamp and returns a proper relative label.
function relativePracticeText(timestamp) {
  if (!timestamp) return "刚刚";
  const diff = Date.now() - timestamp;
  const mins = Math.floor(diff / 60000);
  if (mins < 2)  return "刚刚";
  if (mins < 60) return `${mins}分钟前`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return `${hours}小时前`;
  const days = Math.floor(hours / 24);
  if (days === 1) return "昨天";
  return `${days}天前`;
}

