const MC_CATS = ["全部", "开场挨拶", "自己紹介", "曲間MC", "煽り", "感動MC", "ラスト前", "アンコール", "エンディング"];
const MC_CAT_CN = { "开场挨拶":"开场挨拶","自己紹介":"自己介绍","曲間MC":"曲间MC","煽り":"煽情互动","感動MC":"感动MC","ラスト前":"最后曲前","アンコール":"安可返场","エンディング":"收场" };

// ===== MC大全 Tab =====
function MCBookTab() {
  const T = useTheme();
  const [mcData, setMcData] = useState(() => {
    const saved = safeLoad("stagebuddy_mc_book", null);
    if (!saved) return MC_BOOK_INIT;
    // 合并：保留用户已有数据，追加 MC_BOOK_INIT 中 id 不存在的新条目
    const savedIds = new Set(saved.map(d => d.id));
    const newEntries = MC_BOOK_INIT.filter(d => !savedIds.has(d.id));
    return newEntries.length > 0 ? [...saved, ...newEntries] : saved;
  });
  const [activeCat, setActiveCat] = useState("全部");
  const [editingId, setEditingId] = useState(null);
  const [editDraft, setEditDraft] = useState({});
  const [showAdd, setShowAdd] = useState(false);
  const [addDraft, setAddDraft] = useState({ cat:"曲間MC", cn:"", note:"" });
  const [search, setSearch] = useState("");
  const nextIdRef = useRef(200);

  useEffect(() => { safeSave("stagebuddy_mc_book", mcData); }, [mcData]);

  const filtered = useMemo(() => {
    return mcData.filter(d => {
      const matchCat = activeCat === "全部" || d.cat === activeCat;
      const q = search.trim().toLowerCase();
      const matchQ = !q || d.cn.toLowerCase().includes(q) || (d.note||"").toLowerCase().includes(q) || d.cat.toLowerCase().includes(q);
      return matchCat && matchQ;
    });
  }, [mcData, activeCat, search]);

  const catCount = (cat) => cat === "全部" ? mcData.length : mcData.filter(d => d.cat === cat).length;

  const startEdit = (item) => { setEditingId(item.id); setEditDraft({ ...item }); };
  const cancelEdit = () => { setEditingId(null); setEditDraft({}); };
  const saveEdit = () => {
    setMcData(prev => prev.map(d => d.id === editingId ? { ...d, ...editDraft } : d));
    setEditingId(null);
  };
  const deleteItem = (id) => setMcData(prev => prev.filter(d => d.id !== id));
  const addItem = () => {
    if (!addDraft.cn.trim()) return;
    const newId = nextIdRef.current++;
    setMcData(prev => [...prev, { id: newId, ...addDraft, jp: MC_CAT_CN[addDraft.cat] || addDraft.cat, glyph: "·" }]);
    setAddDraft({ cat:"曲間MC", cn:"", note:"" });
    setShowAdd(false);
  };

  const glyphColor = (glyph) => ({
    "·": T.primary, "○": T.accent2 || T.primary, "…": T.primary,
    "✕": T.primaryDeep || T.primary, "—": T.textSub || T.primary
  }[glyph] || T.primary);

  const inputStyle = {
    width:"100%", padding:"8px 10px",
    background: `${T.glassBg}${T.dark ? "0.18)" : "0.45)"}`,
    border: `1px solid ${T.glassBorder}`, borderRadius:10,
    color: T.text, fontSize:12, fontFamily:"inherit",
    outline:"none", resize:"vertical",
    WebkitBackdropFilter:"blur(8px)", backdropFilter:"blur(8px)",
  };

  return (
    <div style={{ padding:"16px 14px 20px" }}>
      {/* 标题 */}
      <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:14 }}>
        <Residue glyph="·" size={1.1} color={T.primary} />
        <div>
          <p style={{ fontSize:15, fontWeight:700, color:T.text, margin:0, fontFamily:"'Shippori Mincho', serif", letterSpacing:1 }}>MC大全</p>
          <p style={{ fontSize:10, color:T.textLight, margin:0, letterSpacing:0.5 }}>地偶ライブMCフレーズ集</p>
        </div>
        <button
          onClick={() => setShowAdd(v => !v)}
          style={{ marginLeft:"auto", padding:"5px 14px", borderRadius:20, border:`1px solid ${T.primary}55`, background:`${T.primary}18`, color:T.primary, fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>
          {showAdd ? "取消" : "+ 新增"}
        </button>
      </div>

      {/* 搜索 */}
      <div style={{ marginBottom:12, position:"relative" }}>
        <input
          value={search} onChange={e => setSearch(e.target.value)}
          placeholder="搜索台词、场景…"
          style={{ ...inputStyle, paddingLeft:28, resize:"none" }}
        />
        <span style={{ position:"absolute", left:9, top:"50%", transform:"translateY(-50%)", fontSize:11, color:T.textLight, pointerEvents:"none" }}>○</span>
      </div>

      {/* 分类标签 */}
      <div style={{ display:"flex", gap:5, flexWrap:"wrap", marginBottom:14 }}>
        {MC_CATS.map(cat => {
          const active = activeCat === cat;
          return (
            <button key={cat} onClick={() => setActiveCat(cat)} style={{
              padding:"4px 10px", borderRadius:20, border:`1px solid ${active ? T.primary : T.glassBorder}`,
              background: active ? `${T.primary}28` : "transparent",
              color: active ? T.primary : T.textLight,
              fontSize:10, fontWeight: active ? 700 : 500, cursor:"pointer", fontFamily:"inherit",
              display:"flex", alignItems:"center", gap:4,
            }}>
              {MC_CAT_CN[cat] || cat}
              <span style={{ fontSize:9, opacity:0.7 }}>{catCount(cat)}</span>
            </button>
          );
        })}
      </div>

      {/* 新增表单 */}
      {showAdd && (
        <div style={{ ...glass(0.38, 18), borderRadius:14, padding:14, marginBottom:14, animation:"fadeUp 0.2s ease both" }}>
          <p style={{ fontSize:11, color:T.primary, fontWeight:700, margin:"0 0 10px", letterSpacing:0.5 }}>新增台词</p>
          <select value={addDraft.cat} onChange={e => setAddDraft(p => ({...p, cat:e.target.value}))}
            style={{ ...inputStyle, resize:"none", marginBottom:8 }}>
            {MC_CATS.slice(1).map(c => <option key={c} value={c}>{MC_CAT_CN[c]||c}</option>)}
          </select>
          <textarea value={addDraft.cn} onChange={e => setAddDraft(p => ({...p, cn:e.target.value}))}
            rows={3} placeholder="台词内容（日系风格）…" style={{ ...inputStyle, marginBottom:8 }} />
          <input value={addDraft.note||""} onChange={e => setAddDraft(p => ({...p, note:e.target.value}))}
            placeholder="使用场景备注（可选）" style={{ ...inputStyle, resize:"none", marginBottom:10 }} />
          <button onClick={addItem} style={{
            padding:"8px 20px", borderRadius:12, border:"none",
            background:`linear-gradient(135deg, ${T.primary}50, ${T.primaryDeep||T.primary}38)`,
            color:T.text, fontSize:12, fontWeight:700, cursor:"pointer", fontFamily:"inherit",
          }}>保存</button>
        </div>
      )}

      {/* MC 列表 */}
      {filtered.length === 0 && (
        <div style={{ textAlign:"center", padding:"2.5rem 0", color:T.textLight, fontSize:13 }}>
          <Residue glyph="…" size={1.2} color={T.textLight} />
          <p style={{ marginTop:8 }}>暂无台词</p>
        </div>
      )}

      <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
        {filtered.map((item) => {
          const gc = glyphColor(item.glyph || "·");
          if (editingId === item.id) {
            return (
              <div key={item.id} style={{ ...glass(0.42, 18), borderRadius:14, padding:14, border:`1px solid ${T.primary}55`, animation:"fadeUp 0.15s ease both" }}>
                <select value={editDraft.cat} onChange={e => setEditDraft(p => ({...p, cat:e.target.value}))}
                  style={{ ...inputStyle, resize:"none", marginBottom:8 }}>
                  {MC_CATS.slice(1).map(c => <option key={c} value={c}>{MC_CAT_CN[c]||c}</option>)}
                </select>
                <textarea value={editDraft.cn} onChange={e => setEditDraft(p => ({...p, cn:e.target.value}))}
                  rows={4} style={{ ...inputStyle, marginBottom:8 }} />
                <input value={editDraft.note||""} onChange={e => setEditDraft(p => ({...p, note:e.target.value}))}
                  placeholder="使用场景" style={{ ...inputStyle, resize:"none", marginBottom:10 }} />
                <div style={{ display:"flex", gap:8 }}>
                  <button onClick={saveEdit} style={{ padding:"7px 18px", borderRadius:10, border:"none", background:`${T.primary}38`, color:T.primary, fontSize:12, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>保存</button>
                  <button onClick={cancelEdit} style={{ padding:"7px 12px", borderRadius:10, border:`1px solid ${T.glassBorder}`, background:"transparent", color:T.textLight, fontSize:11, cursor:"pointer", fontFamily:"inherit" }}>取消</button>
                </div>
              </div>
            );
          }
          return (
            <div key={item.id} style={{ ...glass(0.35, 16), borderRadius:14, padding:"12px 14px", position:"relative", overflow:"hidden" }}>
              <CardResidue color={gc} seed={item.id} />
              <div style={{ position:"relative", zIndex:1 }}>
                <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:7 }}>
                  <Residue glyph={item.glyph || "·"} size={0.85} color={gc} pulse={false} />
                  <span style={{ fontSize:10, padding:"2px 8px", borderRadius:10, background:`${gc}22`, color:gc, fontWeight:700, letterSpacing:0.5 }}>
                    {MC_CAT_CN[item.cat] || item.cat}
                  </span>
                  {item.jp && item.jp !== item.cat && (
                    <span style={{ fontSize:9, color:T.textLight, opacity:0.6, marginLeft:"auto", fontFamily:"'Shippori Mincho', serif" }}>{item.jp}</span>
                  )}
                  <div style={{ display:"flex", gap:4, marginLeft: item.jp && item.jp !== item.cat ? 0 : "auto" }}>
                    <button onClick={() => startEdit(item)} style={{ padding:"3px 8px", borderRadius:8, border:`1px solid ${T.glassBorder}`, background:"transparent", color:T.textLight, fontSize:10, cursor:"pointer", fontFamily:"inherit" }}>编辑</button>
                    <button onClick={() => deleteItem(item.id)} style={{ padding:"3px 8px", borderRadius:8, border:`1px solid ${T.glassBorder}`, background:"transparent", color:T.textLight, fontSize:10, cursor:"pointer", fontFamily:"inherit" }}>×</button>
                  </div>
                </div>
                <p style={{ fontSize:13, color:T.text, lineHeight:1.75, margin:"0 0 6px", fontFamily:"'Zen Maru Gothic', sans-serif" }}>{item.cn}</p>
                {item.note && (
                  <p style={{ fontSize:10, color:T.textLight, margin:0, paddingLeft:4, borderLeft:`2px solid ${gc}44`, lineHeight:1.5 }}>{item.note}</p>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function PracticeToolPanel({ sessionStats, onAddEvent }) {
  const [activePanel, setActivePanel] = useState(null);
  const [sectionMarks, setSectionMarks] = useState({});
  const [energy, setEnergy] = useState(null);
  const [spots, setSpots] = useState([]);
  const [quickNote, setQuickNote] = useState("");
  const [noteSaved, setNoteSaved] = useState(false);

  const togglePanel = (p) => setActivePanel(prev => prev === p ? null : p);

  const markSection = (sec) => {
    const next = { ...sectionMarks };
    if (next[sec.id]) { delete next[sec.id]; } else { next[sec.id] = true; }
    setSectionMarks(next);
    onAddEvent?.("section_mark", { section: sec.id, label: sec.label });
  };

  const pickEnergy = (e) => {
    setEnergy(e.id);
    onAddEvent?.("energy", { level: e.id, label: e.label });
  };

  const toggleSpot = (s) => {
    const has = spots.includes(s.id);
    setSpots(has ? spots.filter(x => x !== s.id) : [...spots, s.id]);
    if (!has) onAddEvent?.("spot_tag", { tag: s.id, label: s.label });
  };

  const saveNote = () => {
    if (!quickNote.trim()) return;
    onAddEvent?.("quick_note", { text: quickNote.trim() });
    setNoteSaved(true);
    setTimeout(() => setNoteSaved(false), 1500);
  };

  // Instagram 风格图标 — 24×24 viewBox，2px 描边，圆角 linecap/join
  const JIRAI_ICONS = {
    // 段落 — 对齐文字 / 段落标记
    section: (c) => (
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
        <line x1="3" y1="6"  x2="21" y2="6"  stroke={c} strokeWidth="2" strokeLinecap="round"/>
        <line x1="3" y1="11" x2="17" y2="11" stroke={c} strokeWidth="2" strokeLinecap="round"/>
        <line x1="3" y1="16" x2="21" y2="16" stroke={c} strokeWidth="2" strokeLinecap="round"/>
        <line x1="3" y1="21" x2="14" y2="21" stroke={c} strokeWidth="2" strokeLinecap="round"/>
      </svg>
    ),
    // 状态 — 心形（IG 互动核心图标）
    energy: (c) => (
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
        <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78L12 21.23l8.84-8.84a5.5 5.5 0 000-7.78z"
          stroke={c} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"
        />
      </svg>
    ),
    // 难点 — 闪电 / 警告（IG Stories 快拍感）
    spot: (c) => (
      <svg width="13" height="14" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
        <path d="M13 2L4.5 13.5H11L10 22L20 10H13.5L13 2z"
          stroke={c} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"
        />
      </svg>
    ),
    // 速记 — 书签 / 保存（IG 收藏图标）
    note: (c) => (
      <svg width="12" height="14" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
        <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"
          stroke={c} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"
        />
      </svg>
    ),
    // MC — 麦克风（IG Reels / 直播感）
    mc: (c) => (
      <svg width="13" height="14" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
        <rect x="9" y="2" width="6" height="11" rx="3"
          stroke={c} strokeWidth="2" strokeLinejoin="round"
        />
        <path d="M5 10a7 7 0 0014 0" stroke={c} strokeWidth="2" strokeLinecap="round"/>
        <line x1="12" y1="17" x2="12" y2="21" stroke={c} strokeWidth="2" strokeLinecap="round"/>
        <line x1="8"  y1="21" x2="16" y2="21" stroke={c} strokeWidth="2" strokeLinecap="round"/>
      </svg>
    ),
  };

  const toolBtns = [
    { id: "section", label: "段落" },
    { id: "energy", label: "状态" },
    { id: "spot",   label: "难点" },
    { id: "note",   label: "速记" },
    { id: "mc",     label: "MC"   },
  ];

  const [mcExpanded, setMcExpanded] = useState(null);

  return (
    <div style={{ width: "100%", maxWidth: 320, marginTop: 20 }}>
      <div style={{ display: "flex", justifyContent: "center", gap: 6, marginBottom: 8, flexWrap: "wrap" }}>
        {toolBtns.map(t => {
          const isActive = activePanel === t.id;
          const iconColor = isActive ? _T.primary : _T.textLight;
          return (
            <button key={t.id} onClick={() => togglePanel(t.id)} style={{
              padding: "6px 12px", borderRadius: 12, border: "none", cursor: "pointer",
              ...glass(isActive ? 0.5 : 0.28, 16),
              color: isActive ? _T.primary : _T.textLight, fontSize: 11, fontWeight: 700,
              fontFamily: "inherit", display: "flex", alignItems: "center", gap: 5,
              transform: isActive ? "scale(1.05)" : "scale(1)",
              transition: "all 0.3s cubic-bezier(.175,.885,.32,1.275)",
              filter: isActive ? `drop-shadow(0 0 3px ${_T.primary}55)` : "none",
            }}>
              {JIRAI_ICONS[t.id]?.(iconColor)}
              {t.label}
            </button>
          );
        })}
      </div>

      {activePanel === "section" && (
        <div style={{ ...glass(0.38, 18), borderRadius: 16, padding: 14, animation: "fadeUp 0.25s ease both" }}>
          <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 8px", fontWeight: 600 }}>正在练哪个段落？点一下标记～</p>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
            {SONG_SECTIONS.map(sec => {
              const marked = sectionMarks[sec.id];
              return (
                <button key={sec.id} onClick={() => markSection(sec)} style={{
                  padding: "6px 10px", borderRadius: 10, border: "none", cursor: "pointer",
                  background: marked ? `${_T.primary}20` : inlineBg(0.25),
                  color: marked ? _T.primary : _T.textSub, fontSize: 11, fontWeight: 600,
                  fontFamily: "inherit", display: "flex", alignItems: "center", gap: 4,
                  transform: marked ? "scale(1.06)" : "scale(1)",
                  transition: "all 0.3s cubic-bezier(.175,.885,.32,1.275)"
                }}>
                  <Residue glyph={sec.icon} size={0.7} color={marked ? _T.primary : _T.textLight} />{sec.label}
                </button>
              );
            })}
          </div>
        </div>
      )}

      {activePanel === "energy" && (
        <div style={{ ...glass(0.38, 18), borderRadius: 16, padding: 14, animation: "fadeUp 0.25s ease both" }}>
          <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 8px", fontWeight: 600 }}>现在的状态怎么样？</p>
          <div style={{ display: "flex", gap: 6 }}>
            {ENERGY_LEVELS.map(e => {
              const picked = energy === e.id;
              return (
                <button key={e.id} onClick={() => pickEnergy(e)} style={{
                  flex: 1, padding: "10px 4px", borderRadius: 12, border: "none", cursor: "pointer",
                  background: picked ? `${e.color}20` : inlineBg(0.25),
                  display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
                  fontFamily: "inherit",
                  transform: picked ? "scale(1.08)" : "scale(1)",
                  boxShadow: picked ? `0 0 10px ${e.color}25` : "none",
                  transition: "all 0.35s cubic-bezier(.175,.885,.32,1.275)"
                }}>
                  <span style={{ display: "flex", alignItems: "center", justifyContent: "center", width: 28, height: 28, borderRadius: 8, background: picked ? `${e.color}18` : "transparent", transition: "background 0.22s" }}>
                    {ENERGY_ICONS[e.iconKey]?.(picked ? e.color : _T.textLight)}
                  </span>
                  <span style={{ fontSize: 9, color: picked ? e.color : _T.textLight, fontWeight: 700 }}>{e.label}</span>
                </button>
              );
            })}
          </div>
        </div>
      )}

      {activePanel === "spot" && (
        <div style={{ ...glass(0.38, 18), borderRadius: 16, padding: 14, animation: "fadeUp 0.25s ease both" }}>
          <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 8px", fontWeight: 600 }}>哪里卡住了？标记一下～</p>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
            {SPOT_TAGS.map(s => {
              const active = spots.includes(s.id);
              return (
                <button key={s.id} onClick={() => toggleSpot(s)} style={{
                  padding: "6px 10px", borderRadius: 10, border: "none", cursor: "pointer",
                  background: active ? `${_T.primary}20` : inlineBg(0.25),
                  color: active ? _T.primary : _T.textSub, fontSize: 11, fontWeight: 600,
                  fontFamily: "inherit", display: "flex", alignItems: "center", gap: 4,
                  transform: active ? "scale(1.06)" : "scale(1)",
                  transition: "all 0.3s cubic-bezier(.175,.885,.32,1.275)"
                }}>
                  <Residue glyph={s.icon} size={0.7} color={active ? _T.primary : _T.textLight} />{s.label}
                </button>
              );
            })}
          </div>
          {spots.length > 0 && (
            <p style={{ fontSize: 10, color: _T.primary, margin: "8px 0 0", fontWeight: 600 }}>
              已标记 {spots.length} 个难点，结束后会保存到曲目手帐里哦～
            </p>
          )}
        </div>
      )}

      {activePanel === "note" && (
        <div style={{ ...glass(0.38, 18), borderRadius: 16, padding: 14, animation: "fadeUp 0.25s ease both" }}>
          <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 8px", fontWeight: 600 }}>练到一半想到什么，先记下来～</p>
          <textarea
            value={quickNote}
            onChange={e => setQuickNote(e.target.value)}
            placeholder="副歌第二遍进入要提前半拍… / 这里表情可以再夸张一点…"
            style={{
              width: "100%", minHeight: 64, resize: "none", borderRadius: 12,
              border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3),
              padding: 10, outline: "none", color: _T.text, fontFamily: "inherit", fontSize: 12,
              marginBottom: 8
            }}
          />
          <button onClick={saveNote} style={{
            width: "100%", padding: "10px 0", borderRadius: 12, border: "none", cursor: "pointer",
            background: noteSaved ? `${_T.primary}25` : `linear-gradient(135deg, ${_T.primary}20, ${_T.primaryDeep}12)`,
            color: noteSaved ? _T.primary : _T.primaryDeep, fontSize: 12, fontWeight: 700,
            fontFamily: "inherit", transition: "all 0.3s"
          }}>
            {noteSaved ? "·" : "记录"}
          </button>
        </div>
      )}

      {activePanel === "mc" && (
        <div style={{ ...glass(0.38, 18), borderRadius: 16, padding: 14, animation: "fadeUp 0.25s ease both" }}>
          <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 8px", fontWeight: 600 }}>MC话题模板～选一个提前想想怎么说</p>
          {MC_TEMPLATES.map(tpl => {
            const isOpen = mcExpanded === tpl.id;
            return (
              <div key={tpl.id} style={{ marginBottom: 4 }}>
                <button onClick={() => setMcExpanded(isOpen ? null : tpl.id)} style={{
                  width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between",
                  padding: "8px 0", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit",
                  borderBottom: `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}`
                }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                    <span style={{ fontSize: 14 }}>{tpl.icon}</span>
                    <span style={{ fontSize: 12, color: _T.text, fontWeight: 600 }}>{tpl.title}</span>
                  </div>
                  <span style={{ fontSize: 10, color: _T.textLight, transform: isOpen ? "rotate(180deg)" : "rotate(0)", transition: "transform 0.3s" }}>▼</span>
                </button>
                {isOpen && (
                  <div style={{ padding: "6px 0 6px 22px", animation: "fadeUp 0.2s ease both" }}>
                    {tpl.lines.map((line, li) => (
                      <p key={li} style={{ fontSize: 11, color: _T.textSub, margin: "0 0 4px", lineHeight: 1.6, cursor: "pointer" }}
                        onClick={() => { setQuickNote(prev => prev ? prev + "\n" + line : line); setActivePanel("note"); }}
                      >
                        <Residue glyph="·" size={0.5} color={_T.textLight} style={{ marginRight: 4 }} />{line}
                      </p>
                    ))}
                    <p style={{ fontSize: 9, color: _T.textLight, margin: "4px 0 0", opacity: 0.6 }}>点击句子可以复制到速记里编辑哦～</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

function PracticeTab({ practicing, currentSong, practiceTime, onStartPractice, onEndPractice, onAgain, onSmooth, onViewSongs, sessionStats, focusText, songs, onPracticeEvent, trainingSessions, onAddSong, onDeleteSong, onUpdateNote }) {
  const [showHistory, setShowHistory] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);
  const [newTitle, setNewTitle] = useState("");
  const [editingNoteId, setEditingNoteId] = useState(null);
  const [draftNote, setDraftNote] = useState("");
  const [runPhase, setRunPhase] = useState("running"); // running | judging
  const [runCount, setRunCount] = useState(1);
  const [runSpots, setRunSpots] = useState([]);
  const [showRunLog, setShowRunLog] = useState(false);
  const [runLog, setRunLog] = useState([]); // [{run, result, spots, note}]
  const [runNote, setRunNote] = useState("");

  const RUN_SPOT_OPTIONS = [
    { id: "pitch", label: "音准", icon: "·" },
    { id: "choreo", label: "动作", icon: "·" },
    { id: "lyrics", label: "歌词", icon: "·" },
    { id: "transition", label: "转场", icon: "·" },
    { id: "expression", label: "表情", icon: "·" },
    { id: "breath", label: "气息", icon: "·" },
    { id: "timing", label: "拍子", icon: "·" },
  ];

  const RUN_RESULTS = [
    { id: "perfect", label: "通过", desc: "没有卡住",  color: "#6A9A7A", emoji: "○" },
    { id: "ok",      label: "大致", desc: "有瑕疵",    color: "#E8A64A", emoji: "·" },
    { id: "stuck",   label: "断了", desc: "某处中断",  color: "#F0826A", emoji: "✕" },
    { id: "restart", label: "崩溃", desc: "无法继续",  color: "#B39DDB", emoji: "—" },
  ];

  // Instagram / TikTok 风格练习结果图标
  const RUN_RESULT_ICONS = {
    perfect: (color) => (
      <svg width="36" height="36" viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg">
        {/* 外圈渐变背景 */}
        <circle cx="24" cy="24" r="22" fill={color} fillOpacity="0.12"/>
        <circle cx="24" cy="24" r="18" fill={color} fillOpacity="0.08"/>
        {/* TikTok 对勾 — 粗圆角 */}
        <path d="M14 25l7 7 13-14" stroke={color} strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"/>
        {/* Instagram 圆环高光 */}
        <circle cx="24" cy="24" r="22" stroke={color} strokeWidth="2" strokeOpacity="0.3"/>
        <path d="M12 8 Q14 6 16 8" stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeOpacity="0.5"/>
      </svg>
    ),
    ok: (color) => (
      <svg width="36" height="36" viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg">
        <circle cx="24" cy="24" r="22" fill={color} fillOpacity="0.12"/>
        {/* IG 竖拇指 */}
        <path d="M24 14c0 0-2 4-2 7h-6a2 2 0 00-2 2v6a2 2 0 002 2h12l5-2v-9l-3-1-2-5h-4z" fill={color} fillOpacity="0.7" stroke={color} strokeWidth="1.5" strokeLinejoin="round"/>
        <circle cx="24" cy="24" r="22" stroke={color} strokeWidth="2" strokeOpacity="0.3"/>
        {/* 小星点 */}
        <circle cx="34" cy="12" r="1.5" fill={color} fillOpacity="0.6"/>
        <circle cx="38" cy="18" r="1" fill={color} fillOpacity="0.4"/>
      </svg>
    ),
    stuck: (color) => (
      <svg width="36" height="36" viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg">
        <circle cx="24" cy="24" r="22" fill={color} fillOpacity="0.10"/>
        {/* TikTok 闪电 — 卡住 = 能量截断 */}
        <path d="M28 13l-8 13h7l-5 9 10-14h-7z" fill={color} fillOpacity="0.75" stroke={color} strokeWidth="1.5" strokeLinejoin="round"/>
        <circle cx="24" cy="24" r="22" stroke={color} strokeWidth="2" strokeOpacity="0.3"/>
        {/* 断裂感横线 */}
        <path d="M10 32h6M32 32h6" stroke={color} strokeWidth="1.8" strokeLinecap="round" strokeOpacity="0.35"/>
      </svg>
    ),
    restart: (color) => (
      <svg width="36" height="36" viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg">
        <circle cx="24" cy="24" r="22" fill={color} fillOpacity="0.10"/>
        {/* IG / TikTok 循环箭头 — 重来 */}
        <path d="M16 20a8 8 0 1112.5-3.5L32 13" stroke={color} strokeWidth="2.8" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M30 13h5v5" stroke={color} strokeWidth="2.8" strokeLinecap="round" strokeLinejoin="round"/>
        {/* 感叹号中心 */}
        <line x1="24" y1="27" x2="24" y2="32" stroke={color} strokeWidth="2.5" strokeLinecap="round"/>
        <circle cx="24" cy="35.5" r="1.5" fill={color}/>
        <circle cx="24" cy="24" r="22" stroke={color} strokeWidth="2" strokeOpacity="0.28"/>
      </svg>
    ),
  };

  const finishRun = (result) => {
    const entry = { run: runCount, result: result.id, resultLabel: result.label, spots: [...runSpots], note: runNote };
    setRunLog(prev => [...prev, entry]);
    if (result.id === "perfect" || result.id === "ok") {
      onSmooth();
    } else {
      onAgain();
    }
    onPracticeEvent?.("run_finish", { run: runCount, result: result.id, spots: runSpots, note: runNote });
    setRunCount(prev => prev + 1);
    setRunSpots([]);
    setRunNote("");
    setRunPhase("running");
  };

  const toggleRunSpot = (id) => {
    setRunSpots(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  if (practicing && currentSong) {
    return (
      <div style={{ padding: "60px 20px 100px", animation: "fadeUp 0.35s ease both", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "flex-start", minHeight: 580, overflowY: "auto" }}>
        {/* 当前曲目信息 */}
        <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 6 }}>
          <span style={{ fontSize: 10, padding: "3px 8px", borderRadius: 8, background: `${_T.primary}15`, color: _T.primary, fontWeight: 700, textShadow: _T.textGlow || 'none' }}>第 {runCount} 遍</span>
          <Residue glyph="·" size={0.65} color={_T.textLight} />
          <span style={{ fontSize: 10, color: _T.textLight }}>{runPhase === "running" ? "正在跑" : "这遍怎么样？"}</span>
        </div>
        <h1 style={{ fontSize: 14, fontWeight: 800, color: _T.text, margin: "0 0 4px", fontFamily: "'Shippori Mincho', serif" }}>{currentSong.title}</h1>
        <p style={{ fontSize: 11, color: _T.textSub, margin: "0 0 6px", textAlign: "center" }}>{focusText}</p>

        {/* 计时器 + 本次统计 */}
        <p style={{ fontSize: 32, color: _T.textLight, margin: "12px 0 10px", fontWeight: 300, fontFamily: "monospace", letterSpacing: 4 }}>{formatDuration(practiceTime)}</p>
        <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
          <div style={{ ...glass(0.3, 14), borderRadius: 10, padding: "5px 10px", display: "flex", alignItems: "center", gap: 4 }}>
            <Residue glyph="·" size={0.65} color={_T.textLight} />
            <span style={{ fontSize: 10, color: _T.textLight }}>共跑了 {runCount - 1 + (runPhase === "running" ? 0 : 0)} 遍</span>
          </div>
          <div style={{ ...glass(0.3, 14), borderRadius: 10, padding: "5px 10px", display: "flex", alignItems: "center", gap: 4 }}>
            <Residue glyph="○" size={0.65} color={_T.textLight} />
            <span style={{ fontSize: 10, color: _T.textLight }}>顺利 {sessionStats.passes} 遍</span>
          </div>
        </div>

        {/* Phase: Running — 跑的过程中，只有一个大按钮「这遍跑完了」 */}
        {runPhase === "running" && (
          <div style={{ width: "100%", maxWidth: 320 }}>
            <button onClick={() => setRunPhase("judging")} style={{
              width: "100%", padding: "18px 0", borderRadius: 18, border: "none", cursor: "pointer",
              background: `linear-gradient(135deg, ${_T.primary}28, ${_T.primaryDeep}18)`,
              backdropFilter: "blur(16px)", color: _T.primaryDeep, fontSize: 16, fontWeight: 800,
              fontFamily: "inherit", boxShadow: `inset 0 1px 0 ${_T.glassHL}`, borderTop: `1px solid ${_T.primary}20`,
              marginBottom: 12
            }}>
              这遍结束
            </button>
            <p style={{ fontSize: 10, color: _T.textLight, textAlign: "center", margin: 0, lineHeight: 1.5 }}>
              从头到尾跑一遍「{currentSong.title}」<br />跑完了再点上面的按钮，告诉我这遍感觉怎么样～
            </p>
          </div>
        )}

        {/* Phase: Judging — 跑完一遍后的打分环节 */}
        {runPhase === "judging" && (
          <div style={{ width: "100%", maxWidth: 320, animation: "fadeUp 0.3s ease both" }}>
            <p style={{ fontSize: 12, color: _T.text, fontWeight: 700, margin: "0 0 10px", textAlign: "center" }}>第 {runCount} 遍跑完了，整体感觉是——</p>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 14 }}>
              {RUN_RESULTS.map(r => (
                <button key={r.id} onClick={() => finishRun(r)} style={{
                  ...glass(0.4, 18), borderRadius: 16, padding: "16px 10px", border: "none", cursor: "pointer",
                  fontFamily: "inherit", display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
                  transition: "all 0.22s cubic-bezier(.175,.885,.32,1.275)",
                }}>
                  <div style={{
                    width: 56, height: 56, borderRadius: 16,
                    background: `${r.color}12`,
                    display: "flex", alignItems: "center", justifyContent: "center",
                    boxShadow: `0 2px 10px ${r.color}20, inset 0 1px 0 rgba(255,255,255,0.5)`,
                  }}>
                    {RUN_RESULT_ICONS[r.id]?.(r.color)}
                  </div>
                  <span style={{ fontSize: 13, fontWeight: 800, color: r.color, textAlign: "center" }}>{r.label}</span>
                  <span style={{ fontSize: 9, color: _T.textLight, textAlign: "center", lineHeight: 1.3 }}>{r.desc}</span>
                </button>
              ))}
            </div>

            <div style={{ ...glass(0.35, 16), borderRadius: 14, padding: 12, marginBottom: 10 }}>
              <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 8px", fontWeight: 600 }}>这遍哪里卡了？（可多选）</p>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                {RUN_SPOT_OPTIONS.map(s => {
                  const active = runSpots.includes(s.id);
                  return (
                    <button key={s.id} onClick={() => toggleRunSpot(s.id)} style={{
                      padding: "5px 10px", borderRadius: 10, border: "none", cursor: "pointer",
                      background: active ? `${_T.primary}20` : inlineBg(0.25),
                      color: active ? _T.primary : _T.textSub, fontSize: 10, fontWeight: 600,
                      fontFamily: "inherit", display: "flex", alignItems: "center", gap: 3,
                      transform: active ? "scale(1.05)" : "scale(1)",
                      transition: "all 0.25s cubic-bezier(.175,.885,.32,1.275)"
                    }}>
                      <Residue glyph={s.icon} size={0.65} color={active ? _T.primary : _T.textSub} />{s.label}
                    </button>
                  );
                })}
              </div>
            </div>

            <input
              value={runNote}
              onChange={e => setRunNote(e.target.value)}
              placeholder="副歌第二句进晚了 / B段走位忘了…"
              style={{
                width: "100%", padding: "9px 12px", borderRadius: 12, fontSize: 11,
                border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3),
                color: _T.text, outline: "none", fontFamily: "inherit", marginBottom: 10
              }}
            />
          </div>
        )}

        <PracticeToolPanel sessionStats={sessionStats} onAddEvent={(type, payload) => onPracticeEvent?.(type, payload)} />

        {/* 本次跑遍记录 */}
        {runLog.length > 0 && (
          <div style={{ width: "100%", maxWidth: 320, marginTop: 16 }}>
            <button onClick={() => setShowRunLog(!showRunLog)} style={{
              width: "100%", display: "flex", justifyContent: "space-between", alignItems: "center",
              background: "none", border: "none", cursor: "pointer", fontFamily: "inherit", padding: "6px 0"
            }}>
              <span style={{ fontSize: 11, color: _T.textLight, fontWeight: 600 }}>跑遍记录 ({runLog.length}遍)</span>
              <span style={{ fontSize: 10, color: _T.textLight, transform: showRunLog ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.3s" }}>▼</span>
            </button>
            {showRunLog && (
              <div style={{ animation: "fadeUp 0.2s ease both" }}>
                {runLog.map((entry, i) => {
                  const r = RUN_RESULTS.find(x => x.id === entry.result);
                  return (
                    <div key={i} style={{ ...glass(0.28, 14), borderRadius: 12, padding: 10, marginTop: 6 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 2 }}>
                        <span style={{ width: 18, height: 18, flexShrink: 0 }}>{RUN_RESULT_ICONS[r?.id]?.(r?.color || _T.textLight)}</span>
                        <span style={{ fontSize: 11, fontWeight: 700, color: r?.color }}>第{entry.run}遍 · {entry.resultLabel}</span>
                      </div>
                      {entry.spots.length > 0 && (
                        <p style={{ fontSize: 9, color: _T.textSub, margin: "2px 0 0" }}>
                          卡点：{entry.spots.map(sid => RUN_SPOT_OPTIONS.find(x => x.id === sid)?.label).filter(Boolean).join("、")}
                        </p>
                      )}
                      {entry.note && <p style={{ fontSize: 9, color: _T.textLight, margin: "2px 0 0" }}>{entry.note}</p>}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        <div style={{ marginTop: 20, display: "flex", gap: 24 }}>
          <button onClick={onViewSongs} style={{ background: "none", border: "none", cursor: "pointer", color: _T.textLight, fontSize: 13, fontFamily: "inherit" }}>换一首试试</button>
          <button onClick={onEndPractice} style={{ background: "none", border: "none", cursor: "pointer", color: _T.textLight, fontSize: 13, fontFamily: "inherit" }}>今天先到这里吧～</button>
        </div>
      </div>
    );
  }

  const handleAddSong = () => {
    if (!newTitle.trim()) return;
    onAddSong?.({ id: Date.now(), title: newTitle.trim(), status: "new", note: "— 刚开始练", lastPractice: "还没练过", practiceCount: 0, retryCount: 0, passCount: 0, callGuide: "" });
    setNewTitle("");
    setShowAddForm(false);
  };

  return (
    <div style={{ padding: "60px 16px 100px", animation: "fadeUp 0.4s ease both" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
        <h2 style={{ fontSize: 20, fontWeight: 800, color: _T.text, margin: 0, fontFamily: "'Shippori Mincho', serif" }}>选一首开始吧～</h2>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <span style={{ fontSize: 11, color: _T.textLight }}>今天 {trainingSessions.filter(s => {
            const d = new Date(s.startedAt || 0); const t = new Date(); return d.toDateString() === t.toDateString();
          }).length} 次</span>
          <button onClick={() => { setEditMode(e => !e); setShowAddForm(false); setEditingNoteId(null); }} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 16, color: editMode ? _T.primary : _T.textLight, padding: "2px 4px", WebkitTapHighlightColor: "transparent" }}>
            {editMode ? "完成" : "✎"}
          </button>
        </div>
      </div>
      <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 16px" }}>不用想太多，开始就好</p>

      {songs.map(s => (
        <div key={s.id} style={{ marginBottom: 10 }}>
          <div style={{ ...glass(0.4, 18), borderRadius: 16, padding: "14px 16px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <button onClick={() => !editMode && onStartPractice(s)} style={{ flex: 1, textAlign: "left", background: "none", border: "none", cursor: editMode ? "default" : "pointer", padding: 0, fontFamily: "inherit", minWidth: 0 }}>
              <p style={{ fontSize: 14, fontWeight: 700, color: _T.text, margin: "0 0 2px" }}>{s.title}</p>
              {editingNoteId === s.id
                ? <input autoFocus value={draftNote} onChange={e => setDraftNote(e.target.value)} onBlur={() => { onUpdateNote?.(s.id, draftNote); setEditingNoteId(null); }} onKeyDown={e => { if (e.key === "Enter") { onUpdateNote?.(s.id, draftNote); setEditingNoteId(null); } }} style={{ fontSize: 11, color: _T.textSub, background: "none", border: "none", borderBottom: `1px solid ${_T.primary}50`, outline: "none", width: "100%", fontFamily: "inherit", padding: "1px 0" }} />
                : <p onClick={() => { if (editMode) { setEditingNoteId(s.id); setDraftNote(s.note || ""); } }} style={{ fontSize: 11, color: _T.textSub, margin: 0, cursor: editMode ? "text" : "default" }}>{s.note || "—"}</p>
              }
            </button>
            <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
              {!editMode && s.practiceCount > 0 && <span style={{ fontSize: 9, color: _T.textLight }}>{s.practiceCount}次</span>}
              {!editMode && <div style={{ width: 8, height: 8, borderRadius: "50%", background: getSongStatusColor(s.status), boxShadow: getSongStatusGlow(s.status) }} />}
              {editMode && <button onClick={() => onDeleteSong?.(s.id)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 18, color: "#e05060", padding: "2px 4px", lineHeight: 1, WebkitTapHighlightColor: "transparent" }}>×</button>}
            </div>
          </div>
        </div>
      ))}

      {/* 新增歌曲 */}
      {editMode && !showAddForm && (
        <button onClick={() => setShowAddForm(true)} style={{ width: "100%", marginBottom: 10, ...glass(0.28, 14), borderRadius: 16, padding: "12px 16px", border: `1.5px dashed ${_T.primary}40`, cursor: "pointer", background: "none", color: _T.primary, fontSize: 13, fontWeight: 600, fontFamily: "inherit", display: "flex", alignItems: "center", justifyContent: "center", gap: 6, WebkitTapHighlightColor: "transparent" }}>
          <span style={{ fontSize: 18, lineHeight: 1 }}>＋</span> 添加歌曲
        </button>
      )}
      {editMode && showAddForm && (
        <div style={{ ...glass(0.38, 18), borderRadius: 16, padding: "14px 16px", marginBottom: 10 }}>
          <input autoFocus value={newTitle} onChange={e => setNewTitle(e.target.value)} onKeyDown={e => { if (e.key === "Enter") handleAddSong(); }} placeholder="歌曲名称" style={{ width: "100%", background: "none", border: "none", borderBottom: `1px solid ${_T.primary}50`, outline: "none", fontSize: 14, fontWeight: 700, color: _T.text, fontFamily: "inherit", padding: "2px 0 4px", marginBottom: 12, boxSizing: "border-box" }} />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={handleAddSong} style={{ flex: 1, padding: "9px 0", borderRadius: 12, border: "none", cursor: "pointer", background: `linear-gradient(135deg, ${_T.primary}30, ${_T.primaryDeep}20)`, color: _T.primaryDeep, fontSize: 13, fontWeight: 700, fontFamily: "inherit" }}>添加</button>
            <button onClick={() => { setShowAddForm(false); setNewTitle(""); }} style={{ flex: 1, padding: "9px 0", borderRadius: 12, border: "none", cursor: "pointer", ...glass(0.32, 14), color: _T.textLight, fontSize: 13, fontFamily: "inherit" }}>取消</button>
          </div>
        </div>
      )}

      {/* NEW: 练习履历 */}
      <button onClick={() => setShowHistory(!showHistory)} style={{ width: "100%", textAlign: "left", ...glass(0.32, 16), borderRadius: 16, padding: 14, border: "none", cursor: "pointer", fontFamily: "inherit", marginTop: 6 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <Residue glyph="…" size={0.8} color={_T.textLight} />
            <span style={{ fontSize: 12, color: _T.text, fontWeight: 600 }}>练习履历</span>
            {trainingSessions.length > 0 && <span style={{ fontSize: 10, color: _T.primary, fontWeight: 700, textShadow: _T.textGlow || 'none' }}>{trainingSessions.length}次</span>}
          </div>
          <span style={{ fontSize: 11, color: _T.textLight, transform: showHistory ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.3s" }}>▼</span>
        </div>
      </button>
      {showHistory && (
        <div style={{ animation: "fadeUp 0.25s ease both", marginTop: 8 }}>
          {trainingSessions.length === 0 ? (
            <p style={{ fontSize: 12, color: _T.textLight, textAlign: "center", padding: 16 }}>还没有练习记录哦，开始第一次吧</p>
          ) : (
            trainingSessions.slice(0, 10).map((sess, i) => (
              <div key={sess.id} style={{ ...glass(0.3, 14), borderRadius: 14, padding: 12, marginBottom: 8 }}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                  <span style={{ fontSize: 13, fontWeight: 700, color: _T.text }}>{sess.songTitle}</span>
                  <span style={{ fontSize: 10, color: _T.textLight }}>{formatDuration(sess.duration)}</span>
                </div>
                <div style={{ display: "flex", gap: 8 }}>
                  <span style={{ fontSize: 10, color: _T.textSub }}>通过 {sess.passes}</span>
                  <span style={{ fontSize: 10, color: _T.textSub }}>重试 {sess.retries}</span>
                </div>
                {sess.summary && <p style={{ fontSize: 11, color: _T.textLight, margin: "4px 0 0", lineHeight: 1.5 }}>{sess.summary}</p>}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}

// ===== PRE-STAGE PANEL =====
const PRE_CHECKS = [
  { id: "costume",  label: "衣装 · 妆容 OK",       icon: "○" },
  { id: "mic",      label: "收音 · 话筒确认",       icon: "·" },
  { id: "hair",     label: "发型 · 蝴蝶结 OK",      icon: "—" },
  { id: "props",    label: "道具 OK（扇 / 手幡）",  icon: "·" },
  { id: "setlist",  label: "歌单顺序背熟",          icon: "○" },
  { id: "mc",       label: "MC脚本确认",            icon: "…" },
  { id: "call",     label: "コール引导准备好",       icon: "·" },
  { id: "exit",     label: "退场路线确认",           icon: "✕" },
];

const MENTAL_OPTIONS = [
  { id: "genki",   label: "气合十足",  emoji: "·", color: "#6A9A7A" },
  { id: "normal",  label: "普通",      emoji: "○", color: "#E8A64A" },
  { id: "nervous", label: "紧张",      emoji: "…", color: "#B39DDB" },
  { id: "tired",   label: "有些累",    emoji: "—", color: "#8B9DAF" },
];

function BreathBox({ onDone }) {
  const [phase, setPhase] = useState("idle"); // idle | in | hold | out | done
  const [count, setCount] = useState(0);
  const timerRef = useRef(null);

  const PHASES = [
    { id: "in",   label: "吸气",  dur: 4, next: "hold" },
    { id: "hold", label: "屏住",  dur: 4, next: "out"  },
    { id: "out",  label: "呼气",  dur: 6, next: "in"   },
  ];
  const cur = PHASES.find(p => p.id === phase);

  const startBreath = () => {
    setPhase("in");
    setCount(4);
  };

  useEffect(() => {
    if (phase === "idle" || phase === "done") return;
    timerRef.current = setInterval(() => {
      setCount(prev => {
        if (prev <= 1) {
          const c = PHASES.find(p => p.id === phase);
          const nextPhase = c?.next;
          if (phase === "out") {
            // one cycle done
            clearInterval(timerRef.current);
            setPhase("done");
            onDone?.();
            return 0;
          }
          const n = PHASES.find(p => p.id === nextPhase);
          setPhase(nextPhase);
          return n?.dur || 4;
        }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, [phase]);

  const T = useTheme();
  const ringColor = phase === "in" ? "#6A9A7A" : phase === "hold" ? _T.primary : "#8B9DAF";
  const ringSize = phase === "in" ? 68 : phase === "hold" ? 62 : 56;

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", padding: "10px 0" }}>
      {phase === "idle" && (
        <button onClick={startBreath} style={{
          padding: "10px 24px", borderRadius: 14, border: "none", cursor: "pointer",
          background: `${_T.primary}18`, color: _T.primaryDeep,
          fontSize: 13, fontWeight: 700, fontFamily: "inherit"
        }}>开始深呼吸</button>
      )}
      {phase === "done" && (
        <p style={{ fontSize: 13, color: "#6A9A7A", fontWeight: 700, margin: 0 }}>完成 · 状态已整理好了</p>
      )}
      {(phase === "in" || phase === "hold" || phase === "out") && (
        <>
          <div style={{
            width: ringSize, height: ringSize, borderRadius: "50%",
            border: `2.5px solid ${ringColor}`,
            display: "flex", alignItems: "center", justifyContent: "center",
            transition: "all 0.8s ease",
            boxShadow: `0 0 14px ${ringColor}40`,
            marginBottom: 8,
          }}>
            <span style={{ fontSize: 22, fontWeight: 300, color: ringColor, fontFamily: "monospace" }}>{count}</span>
          </div>
          <span style={{ fontSize: 12, color: _T.textSub, fontWeight: 600 }}>{cur?.label}</span>
        </>
      )}
    </div>
  );
}

function PreStagePanel({ nextLive, onBack, onFinishLive }) {
  const T = useTheme();
  const [checks, setChecks] = useState(() => PRE_CHECKS.reduce((a, c) => ({ ...a, [c.id]: false }), {}));
  const [mental, setMental] = useState(null);
  const [showBreath, setShowBreath] = useState(false);
  const [breathDone, setBreathDone] = useState(false);
  const [showSetlist, setShowSetlist] = useState(false);
  const [showVenue, setShowVenue] = useState(false);
  const [mintimer, setMintimer] = useState("");
  const [countdown, setCountdown] = useState(null);
  const timerRef = useRef(null);

  const doneCount = Object.values(checks).filter(Boolean).length;
  const total = PRE_CHECKS.length;
  const pct = Math.round((doneCount / total) * 100);

  const startCountdown = () => {
    const mins = parseInt(mintimer);
    if (!mins || mins <= 0) return;
    setCountdown(mins * 60);
    timerRef.current = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) { clearInterval(timerRef.current); return 0; }
        return prev - 1;
      });
    }, 1000);
  };
  useEffect(() => () => clearInterval(timerRef.current), []);

  const selfOrder = nextLive.taiban?.find(a => a.isSelf);

  return (
    <div style={{ padding: "56px 16px 100px", animation: "fadeUp 0.4s ease both", overflowY: "auto" }}>

      {/* ─ Header ─ */}
      <div style={{ textAlign: "center", marginBottom: 20 }}>
        <div style={{ marginBottom: 10, display: "flex", justifyContent: "center" }}>
          <Residue glyph="○" size={1.8} color={_T.textLight} />
        </div>
        <h2 style={{ fontSize: 20, fontWeight: 800, color: _T.text, margin: "0 0 4px", fontFamily: "'Shippori Mincho', serif" }}>本番前チェック</h2>
        <p style={{ fontSize: 11, color: _T.textLight, margin: 0 }}>{nextLive.venue} · {selfOrder ? `出演顺序 ${selfOrder.order}番 · ${selfOrder.time}` : nextLive.holdTime}</p>
      </div>

      {/* ─ Countdown timer ─ */}
      <div style={{ ...glass(0.38, 18), borderRadius: 18, padding: "14px 16px", marginBottom: 12 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
          <Residue glyph="—" size={0.8} color={_T.textLight} />
          <span style={{ fontSize: 12, fontWeight: 700, color: _T.text }}>上台倒计时</span>
        </div>
        {countdown === null ? (
          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <input
              value={mintimer}
              onChange={e => setMintimer(e.target.value.replace(/[^0-9]/g, ""))}
              placeholder="分钟"
              style={{
                flex: 1, padding: "8px 12px", borderRadius: 12, fontSize: 13,
                border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.25),
                color: _T.text, outline: "none", fontFamily: "inherit"
              }}
            />
            <button onClick={startCountdown} style={{
              padding: "8px 18px", borderRadius: 12, border: "none", cursor: "pointer",
              background: `${_T.primary}20`, color: _T.primaryDeep, fontSize: 12, fontWeight: 700, fontFamily: "inherit"
            }}>开始</button>
          </div>
        ) : countdown === 0 ? (
          <p style={{ fontSize: 16, color: _T.primary, fontWeight: 800, textAlign: "center", margin: 0, letterSpacing: 2 }}>GO！</p>
        ) : (
          <div style={{ textAlign: "center" }}>
            <p style={{ fontSize: 34, fontWeight: 200, color: _T.text, margin: "0 0 2px", fontFamily: "monospace", letterSpacing: 4 }}>
              {String(Math.floor(countdown / 60)).padStart(2, "0")}:{String(countdown % 60).padStart(2, "0")}
            </p>
            <button onClick={() => { clearInterval(timerRef.current); setCountdown(null); setMintimer(""); }}
              style={{ fontSize: 10, color: _T.textLight, background: "none", border: "none", cursor: "pointer" }}>取消</button>
          </div>
        )}
      </div>

      {/* ─ Checklist ─ */}
      <div style={{ ...glass(0.38, 18), borderRadius: 18, padding: "14px 16px", marginBottom: 12 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <Residue glyph="·" size={0.8} color={_T.textLight} />
            <span style={{ fontSize: 12, fontWeight: 700, color: _T.text }}>本番前チェックリスト</span>
          </div>
          <span style={{ fontSize: 11, fontWeight: 700, color: pct === 100 ? "#6A9A7A" : _T.primary }}>
            {doneCount}/{total}
          </span>
        </div>
        {/* progress bar */}
        <div style={{ height: 3, borderRadius: 3, background: inlineBg(0.3), marginBottom: 12, overflow: "hidden" }}>
          <div style={{ height: "100%", borderRadius: 3, width: `${pct}%`, background: pct === 100 ? "#6A9A7A" : _T.primary, transition: "width 0.4s ease" }} />
        </div>
        {PRE_CHECKS.map(item => {
          const done = checks[item.id];
          return (
            <button key={item.id} onClick={() => setChecks(p => ({ ...p, [item.id]: !p[item.id] }))} style={{
              width: "100%", textAlign: "left", display: "flex", alignItems: "center", gap: 10,
              padding: "9px 0", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit",
              borderBottom: `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}`,
            }}>
              <span style={{
                width: 18, height: 18, borderRadius: 6, flexShrink: 0,
                border: `1.5px solid ${done ? "#6A9A7A" : _T.glassBorder}`,
                background: done ? "#6A9A7A20" : "transparent",
                display: "flex", alignItems: "center", justifyContent: "center",
                transition: "all 0.2s",
              }}>
                {done && <span style={{ fontSize: 10, color: "#6A9A7A", fontWeight: 800 }}>✓</span>}
              </span>
              <Residue glyph={item.icon} size={0.65} color={done ? "#6A9A7A" : _T.textLight} />
              <span style={{ fontSize: 12, color: done ? _T.textLight : _T.text, fontWeight: done ? 400 : 600, textDecoration: done ? "line-through" : "none", transition: "all 0.2s" }}>{item.label}</span>
            </button>
          );
        })}
      </div>

      {/* ─ Setlist quick view ─ */}
      {nextLive.setlist?.length > 0 && (
        <div style={{ ...glass(0.38, 18), borderRadius: 18, padding: "14px 16px", marginBottom: 12 }}>
          <button onClick={() => setShowSetlist(!showSetlist)} style={{ width: "100%", display: "flex", justifyContent: "space-between", alignItems: "center", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit", padding: 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <Residue glyph="…" size={0.8} color={_T.textLight} />
              <span style={{ fontSize: 12, fontWeight: 700, color: _T.text }}>歌单确认</span>
            </div>
            <span style={{ fontSize: 11, color: _T.textLight, transform: showSetlist ? "rotate(180deg)" : "none", transition: "transform 0.3s" }}>▼</span>
          </button>
          {showSetlist && (
            <div style={{ marginTop: 12, animation: "fadeUp 0.2s ease both" }}>
              {nextLive.setlist.map((item, i) => (
                <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "7px 0", borderBottom: i < nextLive.setlist.length - 1 ? `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}` : "none" }}>
                  <span style={{ width: 20, height: 20, borderRadius: 10, background: item.song ? `${_T.primary}20` : inlineBg(0.3), display: "flex", alignItems: "center", justifyContent: "center", fontSize: 10, fontWeight: 800, color: item.song ? _T.primary : _T.textLight, flexShrink: 0 }}>{i + 1}</span>
                  <div>
                    <p style={{ fontSize: 13, fontWeight: item.song ? 700 : 400, color: item.song ? _T.text : _T.textLight, margin: 0 }}>{item.song || "—"}</p>
                    <p style={{ fontSize: 9, color: _T.textLight, margin: 0 }}>{item.role}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* ─ Venue note ─ */}
      {nextLive.hako?.stageNote && (
        <div style={{ ...glass(0.38, 18), borderRadius: 18, padding: "14px 16px", marginBottom: 12 }}>
          <button onClick={() => setShowVenue(!showVenue)} style={{ width: "100%", display: "flex", justifyContent: "space-between", alignItems: "center", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit", padding: 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <Residue glyph="✕" size={0.8} color={_T.textLight} />
              <span style={{ fontSize: 12, fontWeight: 700, color: _T.text }}>场地注意事项</span>
            </div>
            <span style={{ fontSize: 11, color: _T.textLight, transform: showVenue ? "rotate(180deg)" : "none", transition: "transform 0.3s" }}>▼</span>
          </button>
          {showVenue && (
            <p style={{ fontSize: 12, color: _T.textSub, margin: "10px 0 0", lineHeight: 1.7, animation: "fadeUp 0.2s ease both" }}>
              {nextLive.hako.stageNote}
            </p>
          )}
        </div>
      )}

      {/* ─ Mental state ─ */}
      <div style={{ ...glass(0.38, 18), borderRadius: 18, padding: "14px 16px", marginBottom: 12 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
          <Residue glyph="○" size={0.8} color={_T.textLight} />
          <span style={{ fontSize: 12, fontWeight: 700, color: _T.text }}>现在的状态</span>
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          {MENTAL_OPTIONS.map(opt => {
            const picked = mental === opt.id;
            return (
              <button key={opt.id} onClick={() => setMental(opt.id)} style={{
                flex: 1, padding: "10px 4px", borderRadius: 12, border: "none", cursor: "pointer",
                background: picked ? `${opt.color}20` : inlineBg(0.25),
                display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
                fontFamily: "inherit", transform: picked ? "scale(1.06)" : "scale(1)",
                boxShadow: picked ? `0 0 10px ${opt.color}25` : "none",
                transition: "all 0.3s cubic-bezier(.175,.885,.32,1.275)"
              }}>
                <Residue glyph={opt.emoji} size={1.1} color={picked ? opt.color : _T.textLight} />
                <span style={{ fontSize: 9, color: picked ? opt.color : _T.textLight, fontWeight: 700 }}>{opt.label}</span>
              </button>
            );
          })}
        </div>
        {mental === "nervous" && (
          <p style={{ fontSize: 11, color: _T.textLight, margin: "8px 0 0", textAlign: "center", lineHeight: 1.5 }}>
            紧张 = 认真的证明。深呼吸一次再去吧。
          </p>
        )}
      </div>

      {/* ─ Breathing exercise ─ */}
      <div style={{ ...glass(0.35, 18), borderRadius: 18, padding: "14px 16px", marginBottom: 20 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: breathDone || showBreath ? 12 : 0 }}>
          <Residue glyph="—" size={0.8} color={_T.textLight} />
          <span style={{ fontSize: 12, fontWeight: 700, color: _T.text }}>深呼吸</span>
          {!showBreath && !breathDone && (
            <button onClick={() => setShowBreath(true)} style={{ marginLeft: "auto", padding: "5px 12px", borderRadius: 10, border: "none", cursor: "pointer", background: `${_T.primary}15`, color: _T.primaryDeep, fontSize: 11, fontWeight: 700, fontFamily: "inherit" }}>
              开始
            </button>
          )}
        </div>
        {(showBreath || breathDone) && (
          <BreathBox onDone={() => { setBreathDone(true); setShowBreath(false); }} />
        )}
      </div>

      {/* ─ Buttons ─ */}
      <div style={{ display: "flex", gap: 10 }}>
        <button onClick={onBack} style={{ flex: 1, padding: "14px 0", borderRadius: 16, border: "none", cursor: "pointer", ...glass(0.4, 20), color: _T.textSub, fontSize: 13, fontWeight: 600, fontFamily: "inherit" }}>← 返回</button>
        <button onClick={onFinishLive} style={{ flex: 2, padding: "14px 0", borderRadius: 16, border: "none", cursor: "pointer", background: `linear-gradient(135deg, ${_T.primary}30, ${_T.primaryDeep}20)`, color: _T.primaryDeep, fontSize: 13, fontWeight: 700, fontFamily: "inherit" }}>今天的Live结束</button>
      </div>
    </div>
  );
}

// ===== LIVE TAB =====
function LiveTab({ nextLive, songs, readinessText, onReflection, onFinishLive, onToggleChecklist, onUpdateLive, onOpenSns, onOpenFanNote, onEnterLiveMode }) {
  const [preStage, setPreStage] = useState(false);
  const [showHako, setShowHako] = useState(false);
  const [editingHako, setEditingHako] = useState(false);
  const [hakoEdit, setHakoEdit] = useState({ name: "", capacity: "", stageNote: "" });
  const [hakoSaved, setHakoSaved] = useState(false);
  const [costumeInput, setCostumeInput] = useState(nextLive.costume || "");
  const [costumeSaved, setCostumeSaved] = useState(false);
  const [editingTaiban, setEditingTaiban] = useState(null);
  const [taibanNote, setTaibanNote] = useState("");
  const [editingSetlist, setEditingSetlist] = useState(false);
  const [aiSetlistLoading, setAiSetlistLoading] = useState(false);
  const [aiSetlistSuggestion, setAiSetlistSuggestion] = useState(null);
  const [editingLiveInfo, setEditingLiveInfo] = useState(false);
  const [liveInfoDraft, setLiveInfoDraft] = useState({ name: nextLive.name, venue: nextLive.venue, date: nextLive.date, daysLeft: nextLive.daysLeft, holdTime: nextLive.holdTime });

  const startEditHako = () => {
    setHakoEdit({
      name: nextLive.hako?.name || "",
      capacity: nextLive.hako?.capacity || "",
      stageNote: nextLive.hako?.stageNote || ""
    });
    setEditingHako(true);
  };
  const saveHako = () => {
    onUpdateLive?.({ hako: { ...nextLive.hako, ...hakoEdit }, venue: hakoEdit.name || nextLive.venue });
    setEditingHako(false);
    setHakoSaved(true);
    setTimeout(() => setHakoSaved(false), 1500);
  };

  const saveCostume = () => {
    onUpdateLive?.({ costume: costumeInput });
    setCostumeSaved(true);
    setTimeout(() => setCostumeSaved(false), 1500);
  };

  const saveTaibanNote = (idx) => {
    const newTaiban = [...nextLive.taiban];
    newTaiban[idx] = { ...newTaiban[idx], note: taibanNote };
    onUpdateLive?.({ taiban: newTaiban });
    setEditingTaiban(null);
    setTaibanNote("");
  };

  if (preStage) {
    return <PreStagePanel
      nextLive={nextLive}
      onBack={() => setPreStage(false)}
      onFinishLive={() => { setPreStage(false); onFinishLive(); }}
    />;
  }

  return (
    <div style={{ padding: "60px 16px 100px", animation: "fadeUp 0.4s ease both" }}>
      <div style={{ ...glass(0.45, 24), borderRadius: 22, padding: 22, marginBottom: 14 }}>
        <p style={{ fontSize: 11, color: _T.textLight, margin: "0 0 4px", fontWeight: 600, letterSpacing: 1.5 }}>下一场 Live</p>
        <h1 style={{ fontSize: 30, fontWeight: 800, color: _T.text, margin: "0 0 4px", fontFamily: "'Shippori Mincho', serif" }}>{nextLive.daysLeft}<span style={{ fontSize: 16, fontWeight: 500 }}>天后</span></h1>
        <p style={{ fontSize: 14, color: _T.textSub, margin: "0 0 2px", fontWeight: 600 }}>{nextLive.venue}</p>
        <p style={{ fontSize: 12, color: _T.primary, margin: "0 0 4px" }}>{readinessText}</p>
        <p style={{ fontSize: 12, color: _T.textLight, margin: 0 }}>{nextLive.date} · 演出时长 {nextLive.holdTime || "—"}</p>
      </div>

      {/* 对盘拼场 (enhanced with notes) */}
      {nextLive.taiban && nextLive.taiban.length > 0 && (
        <div style={{ ...glass(0.38, 18), borderRadius: 18, padding: 16, marginBottom: 14 }}>
          <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 10px", fontWeight: 600, letterSpacing: 1 }}>出演顺序</p>
          {nextLive.taiban.map((act, i) => (
            <div key={i}>
              <div style={{
                display: "flex", alignItems: "center", gap: 10, padding: "9px 0",
                borderBottom: (editingTaiban !== i && i < nextLive.taiban.length - 1) ? `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}` : "none"
              }}>
                <span style={{
                  width: 22, height: 22, borderRadius: 11, fontSize: 11, fontWeight: 800,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  background: act.isSelf ? `${_T.primary}25` : inlineBg(0.3),
                  color: act.isSelf ? _T.primary : _T.textLight
                }}>{act.order}</span>
                <div style={{ flex: 1 }}>
                  <span style={{ fontSize: 13, fontWeight: act.isSelf ? 800 : 500, color: act.isSelf ? _T.primary : _T.text }}>
                    {act.name}{act.isSelf ? " ← 我们！" : ""}
                  </span>
                  {act.note && !act.isSelf && <p style={{ fontSize: 10, color: _T.textLight, margin: "2px 0 0" }}>· {act.note}</p>}
                </div>
                <span style={{ fontSize: 11, color: _T.textLight }}>{act.time}</span>
                {!act.isSelf && (
                  <button onClick={() => { setEditingTaiban(editingTaiban === i ? null : i); setTaibanNote(act.note || ""); }}
                    style={{ background: "none", border: "none", cursor: "pointer", fontSize: 10, color: _T.textLight, padding: "2px 4px" }}>·</button>
                )}
              </div>
              {/* NEW: 对盘备注编辑 */}
              {editingTaiban === i && (
                <div style={{ padding: "8px 0 8px 32px", animation: "fadeUp 0.2s ease both" }}>
                  <input
                    value={taibanNote}
                    onChange={e => setTaibanNote(e.target.value)}
                    placeholder="风格 / 粉丝数 / 注意事项…"
                    style={{
                      width: "100%", padding: "8px 10px", borderRadius: 10, fontSize: 11,
                      border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3),
                      color: _T.text, outline: "none", fontFamily: "inherit", marginBottom: 6
                    }}
                  />
                  <button onClick={() => saveTaibanNote(i)} style={{
                    padding: "6px 14px", borderRadius: 10, border: "none", cursor: "pointer",
                    background: `${_T.primary}18`, color: _T.primary, fontSize: 10, fontWeight: 700, fontFamily: "inherit"
                  }}>保存备注</button>
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {/* 场地档案 (editable) */}
      {nextLive.hako && (
        <div style={{ ...glass(0.35, 18), borderRadius: 18, padding: 16, marginBottom: 14 }}>
          <button onClick={() => setShowHako(!showHako)} style={{
            width: "100%", display: "flex", justifyContent: "space-between", alignItems: "center",
            background: "none", border: "none", cursor: "pointer", fontFamily: "inherit", padding: 0
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <Residue glyph="·" size={0.8} color={_T.textLight} />
              <span style={{ fontSize: 12, color: _T.text, fontWeight: 600 }}>场地档案 · {nextLive.hako.name}</span>
            </div>
            <span style={{ fontSize: 11, color: _T.textLight, transform: showHako ? "rotate(180deg)" : "rotate(0)", transition: "transform 0.3s" }}>▼</span>
          </button>
          {showHako && !editingHako && (
            <div style={{ marginTop: 12, animation: "fadeUp 0.25s ease both" }}>
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 10 }}>
                <span style={{ fontSize: 10, padding: "4px 8px", borderRadius: 8, background: `${_T.primary}10`, color: _T.textSub }}>容量 {nextLive.hako.capacity}</span>
                <span style={{ fontSize: 10, padding: "4px 8px", borderRadius: 8, background: `${_T.primary}10`, color: _T.textSub }}>上次 {nextLive.hako.lastVisit}</span>
              </div>
              <p style={{ fontSize: 11, color: _T.textSub, margin: "0 0 8px", lineHeight: 1.7 }}>· {nextLive.hako.stageNote}</p>
              {nextLive.hako.lastSetlist && (
                <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 8px" }}>上次歌单：{nextLive.hako.lastSetlist}</p>
              )}
              <button onClick={startEditHako} style={{
                padding: "6px 14px", borderRadius: 10, border: "none", cursor: "pointer",
                background: inlineBg(0.3), color: _T.textSub, fontSize: 10, fontWeight: 600, fontFamily: "inherit",
                display: "flex", alignItems: "center", gap: 4
              }}>编辑</button>
            </div>
          )}
          {showHako && editingHako && (
            <div style={{ marginTop: 12, animation: "fadeUp 0.25s ease both" }}>
              <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 8px", fontWeight: 600 }}>编辑场地档案</p>
              {[
                { key: "name", label: "场地名称", placeholder: "涩谷 Milkyway" },
                { key: "capacity", label: "容量", placeholder: "约80人" },
                { key: "stageNote", label: "舞台备注", placeholder: "舞台偏小，左右各留一步距离…" },
              ].map(field => (
                <div key={field.key} style={{ marginBottom: 8 }}>
                  <p style={{ fontSize: 9, color: _T.textLight, margin: "0 0 3px" }}>{field.label}</p>
                  {field.key === "stageNote" ? (
                    <textarea
                      value={hakoEdit[field.key]}
                      onChange={e => setHakoEdit(prev => ({ ...prev, [field.key]: e.target.value }))}
                      placeholder={field.placeholder}
                      style={{
                        width: "100%", minHeight: 56, resize: "none", borderRadius: 10, fontSize: 11,
                        border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3),
                        padding: "8px 10px", outline: "none", color: _T.text, fontFamily: "inherit", lineHeight: 1.6
                      }}
                    />
                  ) : (
                    <input
                      value={hakoEdit[field.key]}
                      onChange={e => setHakoEdit(prev => ({ ...prev, [field.key]: e.target.value }))}
                      placeholder={field.placeholder}
                      style={{
                        width: "100%", padding: "8px 10px", borderRadius: 10, fontSize: 11,
                        border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3),
                        color: _T.text, outline: "none", fontFamily: "inherit"
                      }}
                    />
                  )}
                </div>
              ))}
              <div style={{ display: "flex", gap: 8 }}>
                <button onClick={saveHako} style={{
                  flex: 1, padding: "8px 0", borderRadius: 10, border: "none", cursor: "pointer",
                  background: hakoSaved ? `${_T.primary}25` : `linear-gradient(135deg, ${_T.primary}20, ${_T.primaryDeep}12)`,
                  color: hakoSaved ? _T.primary : _T.primaryDeep, fontSize: 11, fontWeight: 700, fontFamily: "inherit"
                }}>{hakoSaved ? "·" : "保存"}</button>
                <button onClick={() => setEditingHako(false)} style={{
                  padding: "8px 14px", borderRadius: 10, border: "none", cursor: "pointer",
                  ...glass(0.3, 14), color: _T.textLight, fontSize: 11, fontFamily: "inherit"
                }}>取消</button>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Live信息编辑 */}
      <div style={{ ...glass(0.42, 22), borderRadius: 22, padding: 20, marginBottom: 14 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: editingLiveInfo ? 14 : 0 }}>
          <div>
            <p style={{ fontSize: 11, color: _T.textLight, margin: "0 0 2px", fontWeight: 600 }}>Live信息</p>
            {!editingLiveInfo && (
              <>
                <p style={{ fontSize: 17, fontWeight: 800, color: _T.text, margin: "0 0 2px", fontFamily: "'Shippori Mincho', serif" }}>{nextLive.name}</p>
                <p style={{ fontSize: 11, color: _T.textLight, margin: 0 }}>{nextLive.venue} · {nextLive.date} · {nextLive.holdTime}</p>
              </>
            )}
          </div>
          <button onClick={() => { setEditingLiveInfo(!editingLiveInfo); setLiveInfoDraft({ name: nextLive.name, venue: nextLive.venue, date: nextLive.date, daysLeft: nextLive.daysLeft, holdTime: nextLive.holdTime }); }} style={{ background: "none", border: "none", cursor: "pointer", color: _T.textLight, fontSize: 11, fontFamily: "inherit" }}>{editingLiveInfo ? "取消" : "编辑"}</button>
        </div>
        {editingLiveInfo && (
          <div style={{ animation: "fadeUp 0.2s ease both" }}>
            {[{ key: "name", label: "Live名称", placeholder: "涩谷银河定期公演" }, { key: "venue", label: "场地", placeholder: "涩谷 Milkyway" }, { key: "date", label: "日期", placeholder: "3月18日 (火)" }, { key: "daysLeft", label: "倒计时（天）", placeholder: "3" }, { key: "holdTime", label: "演出时长", placeholder: "25分" }].map(f => (
              <div key={f.key} style={{ marginBottom: 8 }}>
                <p style={{ fontSize: 9, color: _T.textLight, margin: "0 0 3px" }}>{f.label}</p>
                <input value={liveInfoDraft[f.key] || ""} onChange={e => setLiveInfoDraft(d => ({ ...d, [f.key]: e.target.value }))} placeholder={f.placeholder}
                  style={{ width: "100%", padding: "8px 10px", borderRadius: 10, fontSize: 12, border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3), color: _T.text, outline: "none", fontFamily: "inherit" }} />
              </div>
            ))}
            <button onClick={() => { onUpdateLive?.({ ...liveInfoDraft, daysLeft: parseInt(liveInfoDraft.daysLeft) || nextLive.daysLeft }); setEditingLiveInfo(false); }} style={{ width: "100%", padding: "10px 0", borderRadius: 12, border: "none", cursor: "pointer", background: `${_T.primary}20`, color: _T.primary, fontSize: 12, fontWeight: 700, fontFamily: "inherit" }}>保存</button>
          </div>
        )}
      </div>

      {/* 歌单（可编辑 + AI建议） */}
      <div style={{ ...glass(0.38, 18), borderRadius: 18, padding: 18, marginBottom: 14 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <p style={{ fontSize: 12, color: _T.textLight, margin: 0, fontWeight: 600, letterSpacing: 1 }}>本场歌单</p>
          <div style={{ display: "flex", gap: 6 }}>
            <button onClick={async () => {
              setAiSetlistLoading(true); setAiSetlistSuggestion(null);
              const songList = (songs||[]).map(s => `${s.title}（${getSongStatusLabel(s.status)}，练过${s.practiceCount||0}次）`).join("、");
              const roles = nextLive.setlist.map(s => s.role).join("、");
              try {
                const r = await fetch("https://api.anthropic.com/v1/messages", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 400, system: "你是地下偶像演出策划顾问。根据曲目练习状态给出歌单建议。返回JSON：{\"suggestion\":[{\"role\":\"角色名\",\"song\":\"曲目\",\"reason\":\"5字内理由\"}]}", messages: [{ role: "user", content: `曲目：${songList}\n歌单角色：${roles}\nLive时长：${nextLive.holdTime||'未定'}` }] }) });
                const d = await r.json(); const t = d.content?.find(b => b.type === "text")?.text || "";
                setAiSetlistSuggestion(JSON.parse(t.replace(/```json|```/g, "").trim()).suggestion);
              } catch { setAiSetlistSuggestion(null); }
              setAiSetlistLoading(false);
            }} disabled={aiSetlistLoading} style={{ padding: "4px 10px", borderRadius: 8, border: "none", cursor: "pointer", background: `${_T.primary}14`, color: _T.primary, fontSize: 10, fontWeight: 700, fontFamily: "inherit", opacity: aiSetlistLoading ? 0.5 : 1 }}>
              {aiSetlistLoading ? "AI分析中…" : "✦ AI建议"}
            </button>
            <button onClick={() => setEditingSetlist(!editingSetlist)} style={{ padding: "4px 10px", borderRadius: 8, border: "none", cursor: "pointer", background: editingSetlist ? `${_T.primary}20` : inlineBg(0.25), color: editingSetlist ? _T.primary : _T.textSub, fontSize: 10, fontWeight: 700, fontFamily: "inherit" }}>
              {editingSetlist ? "完成" : "编辑"}
            </button>
          </div>
        </div>

        {aiSetlistSuggestion && (
          <div style={{ ...glass(0.45, 14), borderRadius: 14, padding: 12, marginBottom: 12, animation: "fadeUp 0.3s ease both" }}>
            <p style={{ fontSize: 11, color: _T.primary, fontWeight: 700, margin: "0 0 8px" }}>✦ AI建议歌单</p>
            {aiSetlistSuggestion.map((s, i) => (
              <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, padding: "5px 0" }}>
                <span style={{ fontSize: 10, color: _T.textLight, width: 48, flexShrink: 0 }}>{s.role}</span>
                <span style={{ fontSize: 12, fontWeight: 600, color: _T.text }}>{s.song}</span>
                <span style={{ fontSize: 9, color: _T.textLight, marginLeft: "auto" }}>{s.reason}</span>
              </div>
            ))}
            <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
              <button onClick={() => {
                const newSetlist = nextLive.setlist.map((item, i) => { const sugg = aiSetlistSuggestion[i]; return sugg ? { ...item, song: sugg.song } : item; });
                onUpdateLive?.({ setlist: newSetlist }); setAiSetlistSuggestion(null); setEditingSetlist(false);
              }} style={{ flex: 1, padding: "7px 0", borderRadius: 10, border: "none", cursor: "pointer", background: `${_T.primary}20`, color: _T.primary, fontSize: 11, fontWeight: 700, fontFamily: "inherit" }}>应用此建议</button>
              <button onClick={() => setAiSetlistSuggestion(null)} style={{ flex: 1, padding: "7px 0", borderRadius: 10, border: "none", cursor: "pointer", ...glass(0.3, 10), color: _T.textLight, fontSize: 11, fontFamily: "inherit" }}>忽略</button>
            </div>
          </div>
        )}

        {nextLive.setlist.map((item, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 0", borderBottom: i < nextLive.setlist.length - 1 ? `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}` : "none" }}>
            <span style={{ fontSize: 10, fontWeight: 700, color: _T.textLight, width: 50, flexShrink: 0 }}>{item.role}</span>
            {!editingSetlist ? (
              <span style={{ fontSize: 13, fontWeight: 600, color: item.song ? _T.text : _T.textLight, fontStyle: item.song ? "normal" : "italic" }}>{item.song || "—"}</span>
            ) : (
              <select value={item.song || "—"} onChange={e => { const newSetlist = [...nextLive.setlist]; newSetlist[i] = { ...newSetlist[i], song: e.target.value === "—" ? null : e.target.value }; onUpdateLive?.({ setlist: newSetlist }); }} style={{ flex: 1, padding: "6px 8px", borderRadius: 10, fontSize: 12, border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3), color: _T.text, outline: "none", fontFamily: "inherit", cursor: "pointer" }}>
                <option value="—">— 空 —</option>
                {(songs||[]).map(s => <option key={s.id} value={s.title}>{s.title}</option>)}
              </select>
            )}
          </div>
        ))}
      </div>

      {/* 衣装记录 */}
      <div style={{ ...glass(0.35, 18), borderRadius: 18, padding: 16, marginBottom: 14 }}>
        <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 8px", fontWeight: 600 }}>衣装记录</p>
        <div style={{ display: "flex", gap: 8 }}>
          <input
            value={costumeInput}
            onChange={e => setCostumeInput(e.target.value)}
            placeholder="白色连衣裙 + 粉色缎带 + 星星耳环…"
            style={{
              flex: 1, padding: "9px 12px", borderRadius: 12, fontSize: 12,
              border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3),
              color: _T.text, outline: "none", fontFamily: "inherit"
            }}
          />
          <button onClick={saveCostume} style={{
            padding: "9px 14px", borderRadius: 12, border: "none", cursor: "pointer",
            background: costumeSaved ? `${_T.primary}25` : `linear-gradient(135deg, ${_T.primary}20, ${_T.primaryDeep}12)`,
            color: costumeSaved ? _T.primary : _T.primaryDeep, fontSize: 11, fontWeight: 700, fontFamily: "inherit",
            transition: "all 0.3s", whiteSpace: "nowrap"
          }}>
            {costumeSaved ? "·" : "记录"}
          </button>
        </div>
        {nextLive.hako?.lastVisit && (
          <p style={{ fontSize: 9, color: _T.textLight, margin: "6px 0 0", opacity: 0.6 }}>上次在这个场地是 {nextLive.hako.lastVisit}，注意不要撞衫哦～</p>
        )}
      </div>

      {/* NEW: SNS告知入口 */}
      <button onClick={onOpenSns} style={{ width: "100%", textAlign: "left", ...glass(0.35, 18), borderRadius: 18, padding: 16, border: "none", cursor: "pointer", fontFamily: "inherit", marginBottom: 14 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
          <Residue glyph="·" size={0.8} color={_T.textLight} />
          <span style={{ fontSize: 12, color: _T.text, fontWeight: 600 }}>SNS 告知</span>
          <div style={{ display: "flex", gap: 4 }}>
            {nextLive.snsPrePosted && <span style={{ fontSize: 9, padding: "2px 6px", borderRadius: 6, background: "#4CAF5015", color: "#4CAF50", fontWeight: 700 }}>前</span>}
            {nextLive.snsPostPosted && <span style={{ fontSize: 9, padding: "2px 6px", borderRadius: 6, background: "#4CAF5015", color: "#4CAF50", fontWeight: 700 }}>后</span>}
          </div>
        </div>
        <p style={{ fontSize: 11, color: _T.textLight, margin: 0 }}>演出前后的SNS文案，选一个模板改改就好啦～</p>
      </button>

      {/* NEW: 粉丝手帐入口 */}
      <button onClick={onOpenFanNote} style={{ width: "100%", textAlign: "left", ...glass(0.35, 18), borderRadius: 18, padding: 16, border: "none", cursor: "pointer", fontFamily: "inherit", marginBottom: 14 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
          <Residue glyph="○" size={0.8} color={_T.textLight} />
          <span style={{ fontSize: 12, color: _T.text, fontWeight: 600 }}>粉丝手帐</span>
          {(nextLive.fanNotes?.length || 0) > 0 && <span style={{ fontSize: 10, color: _T.primary, fontWeight: 700, textShadow: _T.textGlow || 'none' }}>{nextLive.fanNotes.length}条记录</span>}
        </div>
        <p style={{ fontSize: 11, color: _T.textLight, margin: 0 }}>记住每一位来看你的人，常连也好新粉也好</p>
      </button>

      <div style={{ ...glass(0.35, 18), borderRadius: 18, padding: 16, marginBottom: 14 }}>
        <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 12px", fontWeight: 600 }}>准备进度</p>
        {nextLive.checklist.map((item, idx) => (
          <button key={item.id} onClick={() => onToggleChecklist(idx)} style={{ width: "100%", display: "flex", alignItems: "center", gap: 10, padding: "10px 0", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit", textAlign: "left", borderBottom: idx < nextLive.checklist.length - 1 ? `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}` : "none" }}>
            <span style={{ width: 18, height: 18, borderRadius: 9, border: `1px solid ${item.done ? _T.primary : _T.textLight}`, background: item.done ? `${_T.primary}22` : "transparent", display: "inline-flex", alignItems: "center", justifyContent: "center", color: item.done ? _T.primary : "transparent", fontSize: 12 }}>✓</span>
            <span style={{ fontSize: 13, color: _T.text }}>{item.label}</span>
          </button>
        ))}
      </div>

      <button onClick={() => onEnterLiveMode?.()} style={{ width: "100%", padding: "16px 0", borderRadius: 18, border: "none", cursor: "pointer", background: `linear-gradient(135deg, ${_T.primary}30, ${_T.primaryDeep}20)`, backdropFilter: "blur(18px)", color: _T.primaryDeep, fontSize: 16, fontWeight: 800, fontFamily: "inherit", boxShadow: `inset 0 1px 0 ${_T.glassHL}, 0 0 20px ${_T.primary}18`, borderTop: `1px solid ${_T.primary}25`, marginBottom: 8, letterSpacing: 1 }}>进入演出模式</button>
      <button onClick={() => setPreStage(true)} style={{ width: "100%", padding: "13px 0", borderRadius: 18, border: "none", cursor: "pointer", background: `linear-gradient(135deg, ${_T.primary}25, ${_T.primaryDeep}15)`, backdropFilter: "blur(18px)", color: _T.primaryDeep, fontSize: 14, fontWeight: 700, fontFamily: "inherit", boxShadow: `inset 0 1px 0 ${_T.glassHL}`, borderTop: `1px solid ${_T.primary}20`, marginBottom: 10 }}>舞台准备</button>
      <button onClick={onReflection} style={{ width: "100%", padding: 10, background: "none", border: "none", cursor: "pointer", color: _T.textLight, fontSize: 13, fontFamily: "inherit" }}>查看复盘 →</button>
    </div>
  );
}

// ===== SPECTRUM TAB =====
function SpectrumTab({ trainingSessions, stageSongs, condition, nextLive, onCycleSongStatus }) {
  const [sel, setSel] = useState(null);
  const [statOpen, setStatOpen] = useState(null);
  const [viewMode, setViewMode] = useState("calendar");
  const [touchPos, setTouchPos] = useState(null);
  const [crackPoints, setCrackPoints] = useState([]);
  const [moodTrail, setMoodTrail] = useState([]);
  const [orbRotation, setOrbRotation] = useState({ x: 0, y: 0 });
  const [orbPressed, setOrbPressed] = useState(false);
  const [pressedCell, setPressedCell] = useState(null);
  const [whisper, setWhisper] = useState({ idx: null, text: "" });
  const orbRef = useRef(null);
  const trailTimerRef = useRef(null);
  const whisperTimerRef = useRef(null);

  const dayData = useMemo(() => {
    const today = new Date(); today.setHours(0,0,0,0);
    return Array.from({ length: 30 }, (_, i) => {
      const day = new Date(today); day.setDate(day.getDate() - (29 - i));
      day.setHours(0,0,0,0);
      const dayEnd = new Date(day); dayEnd.setHours(23,59,59,999);
      const daySessions = trainingSessions.filter(s => {
        const t = s.startedAt || 0;
        return t >= day.getTime() && t <= dayEnd.getTime();
      });
      const practiceMinutes = Math.round(daySessions.reduce((a, s) => a + (s.duration || 0), 0) / 60);
      const filled = daySessions.length > 0;
      // pick a mood from sessions' songs or fallback to spectrum mock
      const mockEntry = spectrum[i];
      return { ...mockEntry, day: i + 1, filled, practiceCount: daySessions.length, practiceMinutes, sessions: daySessions };
    });
  }, [trainingSessions]);

  const weekLabels = ["一", "二", "三", "四", "五", "六", "天"];
  const weekPractice = weekLabels.map((label, i) => {
    const today = new Date(); today.setHours(0,0,0,0);
    // Mon=0…Sun=6; today's weekday relative
    const todayDow = (today.getDay() + 6) % 7; // 0=Mon
    const dayOffset = todayDow - i;
    const target = new Date(today); target.setDate(target.getDate() - dayOffset);
    const targetEnd = new Date(target); targetEnd.setHours(23,59,59,999);
    const daySessions = trainingSessions.filter(s => {
      const t = s.startedAt || 0;
      return t >= target.getTime() && t <= targetEnd.getTime();
    });
    const mins = Math.min(90, Math.round(daySessions.reduce((a, s) => a + (s.duration || 0), 0) / 60));
    const moodColor = daySessions.length > 0 ? _T.primary : _T.textLight;
    return { label, mins, color: moodColor, moodColor };
  });
  const songFreq = stageSongs.map(s => ({
    title: s.title, count: s.practiceCount || 0, status: s.status, color: getSongStatusColor(s.status)
  })).sort((a, b) => b.count - a.count);
  const filledDays = dayData.filter(d => d.filled).length;
  const totalPracticeMin = dayData.reduce((acc, d) => acc + d.practiceMinutes, 0);
  const avgPerDay = filledDays > 0 ? Math.round(totalPracticeMin / filledDays) : 0;

  // Orb colors from current theme — Morandi low-saturation per theme
  const orbColor1 = _T.orb[0];
  const orbColor2 = _T.orb[1];
  const orbColor3 = _T.orb[2];
  const orbColor4 = _T.orb[3];

  // Dynamic orb palette — all decorative colors derived from theme
  const orbP = useMemo(() => {
    const h2r = (hex) => { const h = hex.replace('#',''); return [parseInt(h.slice(0,2),16),parseInt(h.slice(2,4),16),parseInt(h.slice(4,6),16)]; };
    const [r1,g1,b1] = h2r(orbColor1);
    const [r2,g2,b2] = h2r(orbColor2);
    const [r3,g3,b3] = h2r(orbColor3);
    const [r4,g4,b4] = h2r(orbColor4);
    const [ra,ga,ba] = h2r(_T.orbAccent);
    const rgb = (r,g,b,a) => `rgba(${r},${g},${b},${a})`;
    const mx = (a,b,t) => [Math.round(a[0]+(b[0]-a[0])*t), Math.round(a[1]+(b[1]-a[1])*t), Math.round(a[2]+(b[2]-a[2])*t)];
    const hl = mx([255,255,255],[r1,g1,b1],0.15);
    const dk = mx([r4,g4,b4],[r3,g3,b3],0.3);
    const acLt = mx([ra,ga,ba],[255,255,255],0.35);
    const acDk = mx([ra,ga,ba],[r4,g4,b4],0.5);
    const mid = mx([r2,g2,b2],[ra,ga,ba],0.5);
    return {
      hl95: rgb(...hl,0.95), hl55: rgb(...hl,0.55), hl22: rgb(...hl,0.22),
      c1_98: rgb(r1,g1,b1,0.98), c1_50: rgb(r1,g1,b1,0.5),
      c2_50: rgb(r2,g2,b2,0.5), c2_70: rgb(r2,g2,b2,0.7), c2_85: rgb(r2,g2,b2,0.85),
      c3_65: rgb(r3,g3,b3,0.65), c3_80: rgb(r3,g3,b3,0.8), c3_90: rgb(r3,g3,b3,0.9),
      c4_70: rgb(r4,g4,b4,0.70), c4_75: rgb(r4,g4,b4,0.75),
      ac55: rgb(ra,ga,ba,0.55), ac40: rgb(ra,ga,ba,0.40), ac45: rgb(ra,ga,ba,0.45),
      ac60: rgb(ra,ga,ba,0.60), ac80: rgb(ra,ga,ba,0.80), ac85: rgb(ra,ga,ba,0.85),
      ac70: rgb(ra,ga,ba,0.70), ac35: rgb(ra,ga,ba,0.35), ac25: rgb(ra,ga,ba,0.25),
      ac22: rgb(ra,ga,ba,0.22), ac12: rgb(ra,ga,ba,0.12), ac92: rgb(ra,ga,ba,0.92),
      ac95: rgb(ra,ga,ba,0.95), ac90: rgb(ra,ga,ba,0.90), ac99: rgb(ra,ga,ba,0.99),
      dk45: rgb(...dk,0.45), dk25: rgb(...dk,0.25), dk30: rgb(...dk,0.30), dk75: rgb(...dk,0.75),
      dkSolid: `rgb(${r4},${g4},${b4})`,
      acLt60: rgb(...acLt,0.6), acLt70: rgb(...acLt,0.7), acLt80: rgb(...acLt,0.8),
      acDk25: rgb(...acDk,0.25), acDk35: rgb(...acDk,0.35), acDk60: rgb(...acDk,0.6),
      mid55: rgb(...mid,0.55), mid40: rgb(...mid,0.40), mid45: rgb(...mid,0.45),
      mid60: rgb(...mid,0.6), mid70: rgb(...mid,0.70),
    };
  }, [orbColor1, orbColor2, orbColor3, orbColor4, _T.orbAccent]);

  // 3D orb touch handler
  const handleOrbMove = useCallback((e) => {
    const rect = orbRef.current?.getBoundingClientRect();
    if (!rect) return;
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    const x = ((clientX - rect.left) / rect.width - 0.5) * 40;
    const y = ((clientY - rect.top) / rect.height - 0.5) * 40;
    setOrbRotation({ x: -y, y: x });
    setTouchPos({ x: clientX - rect.left, y: clientY - rect.top });
    // Add trail
    setMoodTrail(prev => [...prev.slice(-12), { x: clientX - rect.left, y: clientY - rect.top, color: orbColor2, t: Date.now() }]);
  }, [orbColor2]);

  // Crack on press
  const handleOrbPress = useCallback((e) => {
    setOrbPressed(true);
    const cx = 55, cy = 55;
    // Generate SVG path cracks — jagged lines from center outward
    const newCracks = Array.from({ length: 10 + Math.floor(Math.random() * 4) }, (_, i) => {
      const baseAngle = (Math.PI * 2 / 12) * i + (Math.random() - 0.5) * 0.5;
      const r0 = 3 + Math.random() * 3;
      const totalLen = 28 + Math.random() * 28;
      // Build jagged path with 3-4 segments
      const segs = 3 + Math.floor(Math.random() * 2);
      let d = `M ${cx + Math.cos(baseAngle) * r0} ${cy + Math.sin(baseAngle) * r0}`;
      let pathLen = 0;
      let lastX = cx + Math.cos(baseAngle) * r0;
      let lastY = cy + Math.sin(baseAngle) * r0;
      for (let s = 1; s <= segs; s++) {
        const frac = s / segs;
        const jitter = (Math.random() - 0.5) * 0.5;
        const a = baseAngle + jitter;
        const r = r0 + totalLen * frac;
        const nx = cx + Math.cos(a) * r;
        const ny = cy + Math.sin(a) * r;
        d += ` L ${nx} ${ny}`;
        pathLen += Math.sqrt((nx - lastX) ** 2 + (ny - lastY) ** 2);
        lastX = nx; lastY = ny;
      }
      // Sub-branch from midpoint
      const midR = r0 + totalLen * 0.45;
      const branchAngle = baseAngle + (Math.random() > 0.5 ? 0.5 : -0.5);
      const branchLen = 8 + Math.random() * 12;
      const bd = `M ${cx + Math.cos(baseAngle) * midR} ${cy + Math.sin(baseAngle) * midR} L ${cx + Math.cos(branchAngle) * (midR + branchLen)} ${cy + Math.sin(branchAngle) * (midR + branchLen)}`;
      return { d, bd, pathLen: Math.ceil(pathLen), branchLen: Math.ceil(branchLen + 10), delay: Math.random() * 0.08 };
    });
    setCrackPoints(newCracks);
    setTimeout(() => setCrackPoints([]), 1500);
  }, []);

  // Fade trail
  useEffect(() => {
    trailTimerRef.current = setInterval(() => {
      setMoodTrail(prev => prev.filter(p => Date.now() - p.t < 2000));
    }, 200);
    return () => clearInterval(trailTimerRef.current);
  }, []);

  // ── 地雷系动态话术系统：时间段 × 情绪类型 × 语气变体 ──────────────────
  // 原则：私密、轻占有、略不安、像低声自言自语
  // 不说"我爱你"，只说"这件事我记住了"
  const JIRAI_CORPUS = {
    // 时间段 (hour → label)
    getTimeSlot: (h) => {
      if (h >= 5 && h < 11) return "morning";
      if (h >= 11 && h < 17) return "noon";
      if (h >= 17 && h < 23) return "evening";
      return "latenight";
    },
    // 情绪类型映射
    getEmotionSlot: (emotion) => {
      const map = {
        "怀旧": "nostalgic", "忧伤": "sad", "平静": "calm",
        "快乐": "happy", "激昂": "intense", "浪漫": "romantic", "温暖": "warm",
      };
      return map[emotion] || "calm";
    },
    // 话术库：[时间段][情绪类型] → 话术数组
    lines: {
      morning: {
        nostalgic: ["早上想到你…又想到了","这件事我没有忘","……早","还记得的"],
        sad:       ["一个人的早上","醒了，但是—","今天也…嗯","没关系的，应该"],
        calm:      ["平静地记下","就这样","—早","记录了"],
        happy:     ["今天好像还不错","……嗯","被记住了","标记完成"],
        intense:   ["很早就醒了","不知道为什么","今天想做点什么","——已记录"],
        romantic:  ["想联系你但是—","只是路过想了想","……早安","轻轻标记了"],
        warm:      ["今天是暖的","有人知道吗","记一下","早上好"],
      },
      noon: {
        nostalgic: ["中午又想了很多","说不清楚的感觉","…存档","想念某种气味"],
        sad:       ["午休没睡","想了一些事","……—","记着呢"],
        calm:      ["这段时间，过了","标记一下","—","平静地放在这里"],
        happy:     ["今天吃了好吃的","记下来了","……嗯？","被我看到了"],
        intense:   ["好烦躁啊","但我记住了","……算了","放在这里先"],
        romantic:  ["想你的话不说出口","只是标记了","……","悄悄记下"],
        warm:      ["暖暖的这天","我记住了","存了","……很好"],
      },
      evening: {
        nostalgic: ["傍晚是最危险的","想了你很久","……放在这里了","说不出来的"],
        sad:       ["今天不太好","但我记住了","……嗯","标记，然后继续"],
        calm:      ["天黑了，记一下","……—","被我收着了","平静地结束"],
        happy:     ["今天好呀","存起来了","……嗯嗯","被记住了"],
        intense:   ["晚上情绪很乱","但还是记了","……","放这里先不管它"],
        romantic:  ["你出现在傍晚","被我偷偷记下了","……","轻轻的"],
        warm:      ["傍晚的暖光","记下了","……嗯","被我收好了"],
      },
      latenight: {
        nostalgic: ["…深夜又想了","不该想的都想了","——记录了","凌晨的痕迹"],
        sad:       ["睡不着在记","……—","只是不想忘","记着，就够了"],
        calm:      ["深夜记一下","——","…—","放这里不动了"],
        happy:     ["深夜还是高兴着","……被记下了","偷偷存起来","嗯，挺好的"],
        intense:   ["凌晨还没睡","情绪有点满","……记住了","放在这里"],
        romantic:  ["想你想到很晚","不会告诉你的","……悄悄记下","只有我知道"],
        warm:      ["深夜是暖的","……记了","被收好了","不告诉别人"],
      },
    },
  };

  const pickWhisper = useCallback((emotion) => {
    const h = new Date().getHours();
    const tSlot = JIRAI_CORPUS.getTimeSlot(h);
    const eSlot = JIRAI_CORPUS.getEmotionSlot(emotion);
    const pool = JIRAI_CORPUS.lines[tSlot][eSlot] || JIRAI_CORPUS.lines[tSlot]["calm"];
    return pool[Math.floor(Math.random() * pool.length)];
  }, []);

  const handleCellPress = useCallback((idx, d) => {
    setPressedCell(idx);
    setSel(d);
    // Show whisper only for filled days
    if (d.filled) {
      clearTimeout(whisperTimerRef.current);
      setWhisper({ idx, text: pickWhisper(d.emotion), emotion: d.emotion, color: d.color });
      whisperTimerRef.current = setTimeout(() => setWhisper({ idx: null, text: "" }), 2200);
    }
    // Release press after animation
    setTimeout(() => setPressedCell(null), 400);
  }, [pickWhisper]);

  const liquidGlassContainer = {
    ...glass(0.38, 20),
    position: "relative",
    borderRadius: 20,
    overflow: "hidden",
  };
  const liquidGlassInner = {
    borderRadius: 18,
    background: "transparent",
    position: "relative",
    overflow: "hidden",
  };
  const specularHL = { display: "none" };

  return (
    <div style={{ padding: "60px 16px 100px", animation: "fadeUp 0.4s ease both" }}>
      <style>{`
        @keyframes orbFloat {0%,100% { transform: translateY(0px); } 50% { transform: translateY(-6px); } }
        @keyframes cellBreathe {
          0%,100% { box-shadow: var(--cell-glow-off); }
          50% { box-shadow: var(--cell-glow-on); }
        }
        @keyframes cellCollapse {
          0% { transform: scale(1); filter: blur(0px) brightness(1); }
          18% { transform: scale(0.88); filter: blur(1.2px) brightness(1.08); }
          40% { transform: scale(1.06); filter: blur(0px) brightness(1.04); }
          55% { transform: scale(0.97); filter: blur(0px) brightness(1.01); }
          70% { transform: scale(1.02); filter: blur(0px) brightness(1); }
          100% { transform: scale(1); filter: blur(0px) brightness(1); }
        }
        @keyframes whisperIn {
          0% { opacity: 0; transform: translateY(4px) scale(0.92); filter: blur(3px); }
          30% { opacity: 1; transform: translateY(0px) scale(1); filter: blur(0px); }
          75% { opacity: 0.9; }
          100% { opacity: 0; transform: translateY(-6px) scale(0.96); filter: blur(2px); }
        }
        @keyframes cellInnerGlow {
          0% { opacity: 0; transform: scale(0.5); }
          20% { opacity: 0.7; transform: scale(1.1); }
          60% { opacity: 0.35; transform: scale(1); }
          100% { opacity: 0; transform: scale(1.2); }
        }
        @keyframes crackGrow {
          0% { stroke-dashoffset: var(--path-len); opacity: 0; }
          8% { opacity: 0.95; stroke-dashoffset: 0; }
          25% { opacity: 0.85; }
          60% { opacity: 0.4; }
          100% { opacity: 0; }
        }
        @keyframes crackBranchGrow {
          0% { stroke-dashoffset: var(--branch-len); opacity: 0; }
          12% { stroke-dashoffset: 0; opacity: 0.8; }
          40% { opacity: 0.5; }
          100% { opacity: 0; }
        }
        @keyframes shockwave {
          0% { r: 3; opacity: 0.9; stroke-width: 3; }
          30% { r: 38; opacity: 0.5; stroke-width: 1.5; }
          70% { r: 50; opacity: 0.15; stroke-width: 0.5; }
          100% { r: 58; opacity: 0; stroke-width: 0.1; }
        }
        @keyframes shockwave2 {
          0% { r: 2; opacity: 0; stroke-width: 2; }
          15% { opacity: 0.7; }
          40% { r: 32; opacity: 0.3; stroke-width: 1; }
          100% { r: 52; opacity: 0; stroke-width: 0.2; }
        }
        @keyframes shockwave3 {
          0% { r: 1; opacity: 0; stroke-width: 1.5; }
          25% { opacity: 0.5; }
          50% { r: 28; opacity: 0.2; stroke-width: 0.8; }
          100% { r: 46; opacity: 0; stroke-width: 0.1; }
        }
        @keyframes orbImpact {
          0% { transform: rotateX(var(--rx)) rotateY(var(--ry)) scale(0.88); }
          12% { transform: rotateX(var(--rx)) rotateY(var(--ry)) scale(1.06); }
          28% { transform: rotateX(var(--rx)) rotateY(var(--ry)) scale(0.97); }
          42% { transform: rotateX(var(--rx)) rotateY(var(--ry)) scale(1.02); }
          60% { transform: rotateX(var(--rx)) rotateY(var(--ry)) scale(0.995); }
          100% { transform: rotateX(var(--rx)) rotateY(var(--ry)) scale(1); }
        }
        @keyframes crackGlowFlash {
          0% { opacity: 0; }
          5% { opacity: 0.7; }
          15% { opacity: 0.3; }
          100% { opacity: 0; }
        }
        @keyframes microShake {
          0% { transform: translate(0,0); }
          10% { transform: translate(-1.5px, 1px); }
          20% { transform: translate(2px, -1.5px); }
          30% { transform: translate(-1px, -1px); }
          40% { transform: translate(1.5px, 1.5px); }
          50% { transform: translate(-0.5px, -0.5px); }
          60% { transform: translate(0.5px, 0.3px); }
          100% { transform: translate(0,0); }
        }
        @keyframes orbSoftBreath {
          0% { filter: brightness(1.25) contrast(1.1); }
          15% { filter: brightness(1.05); }
          100% { filter: brightness(1); }
        }
        @keyframes trailFade { 0% { opacity: 0.5; transform: scale(1); } 100% { opacity: 0; transform: scale(0.3); } }
        @keyframes shatterPulse { 0% { transform: scale(1); opacity:0.5; } 50% { transform: scale(1.02); opacity:0.8; } 100% { transform: scale(1); opacity:0.5; } }
      `}</style>

      <h2 style={{ fontSize: 20, fontWeight: 800, color: _T.text, margin: "0 0 2px", fontFamily: "'Shippori Mincho', serif" }}>情绪光谱 · 3月</h2>
      <p style={{ fontSize: 11, color: _T.textLight, margin: "0 0 16px", letterSpacing: 0.5 }}>情绪光谱</p>

      {/* ====== 3D情绪球 + 液态玻璃容器 ====== */}
      <div style={{ ...liquidGlassContainer, marginBottom: 18 }}>
        <div style={{ ...liquidGlassInner, padding: "20px 16px 16px" }}>
          <div style={specularHL} />
          {/* Refraction edge */}
          <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 1, background: `linear-gradient(90deg, transparent, rgba(255,255,255,${_T.dark ? 0.12 : 0.7}), transparent)`, zIndex: 3 }} />

          <div style={{ display: "flex", alignItems: "center", gap: 16, position: "relative", zIndex: 4 }}>
            {/* 3D Emotion Orb */}
            <div
              ref={orbRef}
              onMouseMove={handleOrbMove}
              onTouchMove={handleOrbMove}
              onMouseDown={handleOrbPress}
              onTouchStart={handleOrbPress}
              onMouseUp={() => setOrbPressed(false)}
              onTouchEnd={() => { setOrbPressed(false); setOrbRotation({ x: 0, y: 0 }); }}
              onMouseLeave={() => { setOrbRotation({ x: 0, y: 0 }); setTouchPos(null); }}
              style={{
                width: 110, height: 110, borderRadius: "50%", position: "relative", cursor: "grab",
                flexShrink: 0, animation: "orbFloat 4s ease-in-out infinite",
                perspective: 600,
              }}
            >
              {/* Orb body — 清透玻璃球：soft gradient + 真实高光 + 薄边缘光 */}
              <div style={{
                width: "100%", height: "100%", borderRadius: "50%",
                background: `
                  radial-gradient(ellipse at ${28 + orbRotation.y * 0.35}% ${24 + orbRotation.x * 0.28}%,
                    rgba(255,255,255,0.72) 0%,
                    ${orbP.c1_98} 8%,
                    ${orbP.c2_85} 28%,
                    ${orbP.c3_80} 58%,
                    ${orbP.c4_75} 80%,
                    ${orbP.c3_90} 100%
                  )`,
                transform: `rotateX(${orbRotation.x}deg) rotateY(${orbRotation.y}deg) scale(${orbPressed ? 0.96 : 1})`,
                transition: orbPressed ? "transform 0.15s ease" : "transform 0.6s cubic-bezier(.25,.1,.25,1)",
                boxShadow: `
                  0 16px 48px ${orbP.c3_65},
                  0 4px 16px ${orbP.c4_70},
                  inset 0 -6px 18px ${orbP.dk30},
                  inset 0 2px 1px rgba(255,255,255,0.85)
                `,
                position: "relative", overflow: "hidden",
                animation: crackPoints.length > 0 ? "orbImpact 0.6s cubic-bezier(.2,.8,.3,1) forwards, microShake 0.35s ease-out" : undefined,
                "--rx": `${orbRotation.x}deg`,
                "--ry": `${orbRotation.y}deg`,
              }}>
                {/* 主高光 — 椭圆光斑，跟随触控偏移 */}
                <div style={{
                  position: "absolute", top: "7%", left: "14%", width: "38%", height: "28%",
                  borderRadius: "50%",
                  background: `radial-gradient(ellipse, rgba(255,255,255,0.90) 0%, rgba(255,255,255,0.50) 40%, transparent 72%)`,
                  transform: `translate(${orbRotation.y * 0.22}px, ${orbRotation.x * 0.14}px)`,
                  transition: "transform 0.25s ease",
                  pointerEvents: "none",
                  filter: "blur(1px)"
                }} />
                {/* 副高光 — 左侧边缘细弧光 */}
                <div style={{
                  position: "absolute", top: "22%", left: "6%", width: "8%", height: "32%",
                  borderRadius: "50%",
                  background: `radial-gradient(ellipse, rgba(255,255,255,0.55) 0%, transparent 80%)`,
                  pointerEvents: "none", filter: "blur(2px)"
                }} />
                {/* 底部反光 — 桌面反射感 */}
                <div style={{
                  position: "absolute", bottom: "6%", left: "22%", right: "22%", height: "10%",
                  borderRadius: "50%",
                  background: `radial-gradient(ellipse, ${orbP.c1_50} 0%, transparent 70%)`,
                  pointerEvents: "none", filter: "blur(3px)", opacity: 0.6
                }} />
                {/* 液体内核 — 柔和漩涡，模糊处理 */}
                <div style={{
                  position: "absolute", inset: "28%", borderRadius: "50%",
                  background: `conic-gradient(from ${orbRotation.y * 3}deg,
                    ${orbP.mid55},
                    ${orbP.c3_65},
                    ${orbP.ac40},
                    ${orbP.mid45},
                    ${orbP.mid55})`,
                  filter: "blur(12px)", opacity: 0.45, transition: "background 0.4s"
                }} />
                {/* 边缘暗晕 — 球体立体感 */}
                <div style={{
                  position: "absolute", inset: 0, borderRadius: "50%",
                  background: `radial-gradient(ellipse at 50% 50%, transparent 55%, ${orbP.dk30} 100%)`,
                  pointerEvents: "none",
                }} />
                {/* SVG 装饰层 — 虚线环 + 心形包含物 */}
                <svg style={{ position: "absolute", inset: 0, width: "100%", height: "100%", pointerEvents: "none", zIndex: 3 }} viewBox="0 0 110 110">
                  {/* 外虚线圈 — 轻盈 */}
                  <circle cx={55} cy={55} r={43}
                    fill="none"
                    stroke={orbP.ac22}
                    strokeWidth="0.7"
                    strokeDasharray="2.5 4"
                    strokeLinecap="round"
                  />
                  {/* 破碎爱心 inclusion */}
                  <g opacity={0.50} transform={`translate(${55 + orbRotation.y * 0.28}, ${55 + orbRotation.x * 0.18}) scale(0.78)`} style={{ transition: "transform 0.35s ease" }}>
                    <path d="M0 -5 C-7 -11, -16 -7, -14 1 C-12 8, -4 14, 0 20"
                      stroke={orbP.ac85} strokeWidth="1.3" fill={orbP.acDk25} strokeLinecap="round"/>
                    <path d="M0 -5 C7 -11, 16 -7, 14 1 C12 8, 4 14, 0 20"
                      stroke={orbP.ac70} strokeWidth="1.3" fill={orbP.acDk35} strokeLinecap="round"/>
                    <polyline points="0,-5 -1.5,1 2,5 -1,10 0,20"
                      stroke={orbP.acLt80} strokeWidth="0.8" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
                  </g>
                  {/* 十字架装饰 */}
                  <g opacity={0.32} transform="translate(82, 26)">
                    <line x1="0" y1="-5" x2="0" y2="5" stroke={orbP.ac80} strokeWidth="0.85" strokeLinecap="round"/>
                    <line x1="-3.5" y1="-1.5" x2="3.5" y2="-1.5" stroke={orbP.ac80} strokeWidth="0.85" strokeLinecap="round"/>
                  </g>
                </svg>
                {/* Mood trail SVG overlay */}
                <svg style={{ position: "absolute", inset: 0, width: "100%", height: "100%", pointerEvents: "none", zIndex: 5 }} viewBox="0 0 110 110">
                  {moodTrail.map((p, i) => (
                    <circle key={i} cx={p.x} cy={p.y} r={4 - i * 0.2}
                      fill={orbP.ac70} opacity={Math.max(0, 1 - (Date.now() - p.t) / 2000)}
                      style={{ animation: "trailFade 2s ease forwards", filter: "blur(2px)" }}
                    />
                  ))}
                </svg>
                {/* === DRAMATIC SHATTER: radial cracks + shockwaves + screen glow === */}
                {crackPoints.length > 0 && (
                  <>
                    {/* Screen-blend glow flash overlay — 冷粉闪 */}
                    <div style={{
                      position: "absolute", inset: -8, borderRadius: "50%",
                      background: `radial-gradient(circle, ${orbP.ac85} 0%, ${orbP.ac45} 40%, transparent 70%)`,
                      mixBlendMode: "screen",
                      animation: "crackGlowFlash 0.8s ease-out forwards",
                      pointerEvents: "none", zIndex: 6,
                    }} />
                    <svg style={{ position: "absolute", inset: 0, width: "100%", height: "100%", pointerEvents: "none", zIndex: 7, mixBlendMode: "screen" }} viewBox="0 0 110 110">
                      {/* Triple shockwave rings — 粉白冲击波 */}
                      <circle cx={55} cy={55} r={3}
                        fill="none" stroke={orbP.ac90} strokeWidth={3}
                        style={{ animation: "shockwave 0.7s cubic-bezier(.1,.5,.3,1) forwards" }}
                      />
                      <circle cx={55} cy={55} r={2}
                        fill="none" stroke={orbP.ac80} strokeWidth={2}
                        style={{ animation: "shockwave2 0.8s cubic-bezier(.1,.5,.3,1) 0.06s forwards", opacity: 0 }}
                      />
                      <circle cx={55} cy={55} r={1}
                        fill="none" stroke={orbP.ac70} strokeWidth={1.5}
                        style={{ animation: "shockwave3 0.9s cubic-bezier(.1,.5,.3,1) 0.12s forwards", opacity: 0 }}
                      />
                      {/* Central flash point */}
                      <circle cx={55} cy={55} r={6}
                        fill={orbP.acLt80} opacity={0.85}
                        style={{ animation: "crackGlowFlash 0.5s ease-out forwards" }}
                      />
                      {/* Radial crack lines — 暗粉紫破裂 */}
                      {crackPoints.map((c, i) => (
                        <g key={i}>
                          <path d={c.d}
                            fill="none"
                            stroke={orbP.c3_90}
                            strokeWidth={3.5}
                            strokeLinecap="round" strokeLinejoin="round"
                            strokeDasharray={c.pathLen}
                            style={{
                              "--path-len": c.pathLen,
                              strokeDashoffset: c.pathLen,
                              animation: `crackGrow 1.2s cubic-bezier(0.05,0.6,0.2,1) ${c.delay}s forwards`,
                              filter: "blur(3px)",
                            }}
                          />
                          {/* Core crack — 亮粉线 */}
                          <path d={c.d}
                            fill="none"
                            stroke={orbP.ac95}
                            strokeWidth={1.2}
                            strokeLinecap="round" strokeLinejoin="round"
                            strokeDasharray={c.pathLen}
                            style={{
                              "--path-len": c.pathLen,
                              strokeDashoffset: c.pathLen,
                              animation: `crackGrow 1.2s cubic-bezier(0.05,0.6,0.2,1) ${c.delay}s forwards`,
                            }}
                          />
                          {/* Ultra-bright center — 冷白光芯 */}
                          <path d={c.d}
                            fill="none"
                            stroke={orbP.hl95}
                            strokeWidth={0.5}
                            strokeLinecap="round" strokeLinejoin="round"
                            strokeDasharray={c.pathLen}
                            style={{
                              "--path-len": c.pathLen,
                              strokeDashoffset: c.pathLen,
                              animation: `crackGrow 1.2s cubic-bezier(0.05,0.6,0.2,1) ${c.delay}s forwards`,
                            }}
                          />
                          {/* Branch — 暗紫分叉 */}
                          <path d={c.bd}
                            fill="none"
                            stroke={orbP.c3_80}
                            strokeWidth={2}
                            strokeLinecap="round"
                            strokeDasharray={c.branchLen}
                            style={{
                              "--branch-len": c.branchLen,
                              strokeDashoffset: c.branchLen,
                              animation: `crackBranchGrow 1s cubic-bezier(0.05,0.6,0.2,1) ${c.delay + 0.05}s forwards`,
                              filter: "blur(2px)",
                            }}
                          />
                          <path d={c.bd}
                            fill="none"
                            stroke={orbP.ac85}
                            strokeWidth={0.6}
                            strokeLinecap="round"
                            strokeDasharray={c.branchLen}
                            style={{
                              "--branch-len": c.branchLen,
                              strokeDashoffset: c.branchLen,
                              animation: `crackBranchGrow 1s cubic-bezier(0.05,0.6,0.2,1) ${c.delay + 0.05}s forwards`,
                            }}
                          />
                        </g>
                      ))}
                    </svg>
                  </>
                )}
              </div>
              {/* Orb — 地雷系暗金属框 + 蕾丝外环 */}
              <div style={{
                position: "absolute", inset: -3, borderRadius: "50%",
                border: `1.5px solid ${orbP.ac45}`,
                boxShadow: `inset 0 0 18px ${orbP.dk25}, 0 0 22px ${orbP.dk30}, 0 0 8px ${orbP.ac25}`,
                pointerEvents: "none"
              }} />
              {/* 蕾丝外环 SVG */}
              <svg style={{ position: "absolute", inset: -6, width: "calc(100% + 12px)", height: "calc(100% + 12px)", pointerEvents: "none", opacity: 0.5 }} viewBox="0 0 122 122">
                <circle cx={61} cy={61} r={58}
                  fill="none"
                  stroke={orbP.ac35}
                  strokeWidth="0.7"
                  strokeDasharray="1.5 3"
                  strokeLinecap="round"
                />
              </svg>
            </div>

            {/* Mood text */}
            <div style={{ flex: 1, minWidth: 0 }}>
              <p style={{ fontSize: 9, color: _T.textLight, margin: "0 0 4px", textTransform: "uppercase", letterSpacing: 2, fontWeight: 600 }}>今日情绪球</p>
              <p style={{ fontSize: 18, fontWeight: 800, color: _T.text, margin: "0 0 2px", fontFamily: "'Shippori Mincho', serif" }}>
                {dayData[dayData.length - 1]?.emotion || "平静"}
              </p>
              <p style={{ fontSize: 11, color: _T.orbAccent, fontWeight: 600, margin: "0 0 8px" }}>
                {dayData[dayData.length - 1]?.word || ""}
              </p>
              <p style={{ fontSize: 9, color: _T.textLight, margin: 0, lineHeight: 1.5 }}>
                触控球体感受流体 · 按压触发破裂
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* ====== 月度概览 — 液态玻璃卡片（点击展开详情）====== */}
      {(() => {
        const stats = [
          {
            value: filledDays, unit: "天", label: "有练习", emoji: "·",
            detail: {
              title: "练习日分布",
              lines: [
                `本月共练习 ${filledDays} 天`,
                `未练习 ${30 - filledDays} 天`,
                filledDays >= 20 ? "— 高频练习，很稳。" : filledDays >= 10 ? "— 节奏基本稳定。" : "— 练习次数偏少，可以多来。",
                `最近一次：${trainingSessions?.[0]?.date ? trainingSessions[0].date.slice(5) + " 练习" : "记录中…"}`,
              ]
            }
          },
          {
            value: avgPerDay, unit: "分", label: "平均/天", emoji: "…",
            detail: {
              title: "练习时长",
              lines: [
                `有练习的天：平均 ${avgPerDay} 分钟`,
                `总练习时长：约 ${Math.round(totalPracticeMin)} 分钟`,
                avgPerDay >= 30 ? "— 时长充裕，继续保持。" : avgPerDay >= 15 ? "— 中等时长，稳步前进。" : "— 每次时间较短，有余地。",
                `共 ${trainingSessions?.length || 0} 次练习记录`,
              ]
            }
          },
          {
            value: songFreq.filter(s => s.status === "smooth").length, unit: "首", label: "稳定", emoji: "○",
            detail: {
              title: "曲目稳定状况",
              lines: [
                `稳定：${songFreq.filter(s => s.status === "smooth").length} 首`,
                `未完成：${songFreq.filter(s => s.status === "almost").length} 首`,
                `新曲：${songFreq.filter(s => s.status === "new").length} 首`,
                songFreq.filter(s => s.status === "smooth").map(s => `「${s.title}」`).join(" ") || "暂无稳定曲目",
              ]
            }
          },
        ];
        return (
          <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
            {stats.map((stat, i) => {
              const isOpen = statOpen === i;
              return (
                <div key={i} style={{ flex: 1, position: "relative" }}>
                  <button
                    onClick={() => setStatOpen(isOpen ? null : i)}
                    style={{
                      width: "100%", border: "none", cursor: "pointer", padding: 0, background: "none",
                      fontFamily: "inherit", display: "block",
                    }}
                  >
                    <div style={{ ...liquidGlassContainer, borderRadius: 18, padding: 1.5 }}>
                      <div style={{
                        ...liquidGlassInner, borderRadius: 17, padding: "12px 8px", textAlign: "center", position: "relative",
                        border: isOpen ? `1px solid ${_T.primary}40` : undefined,
                        background: isOpen ? (_T.dark ? `linear-gradient(145deg, ${_T.primary}18, rgba(255,255,255,0.04))` : `linear-gradient(145deg, ${_T.primary}10, rgba(255,255,255,0.7))`) : undefined,
                        transition: "background 0.3s, border 0.3s",
                      }}>
                        <div style={{ position: "absolute", top: -1, left: "20%", right: "20%", height: 1, background: `linear-gradient(90deg, transparent, rgba(255,255,255,${_T.dark ? 0.1 : 0.6}), transparent)`, zIndex: 2 }} />
                        <Residue glyph={stat.emoji} size={0.9} color={isOpen ? _T.primary : _T.primary} style={{ position: "relative", zIndex: 3 }} />
                        <p style={{ fontSize: 18, fontWeight: 800, color: isOpen ? _T.primary : _T.text, margin: "2px 0 0", position: "relative", zIndex: 3, transition: "color 0.3s" }}>
                          {stat.value}<span style={{ fontSize: 10, fontWeight: 500 }}>{stat.unit}</span>
                        </p>
                        <p style={{ fontSize: 9, color: _T.textLight, margin: 0, position: "relative", zIndex: 3 }}>{stat.label}</p>
                      </div>
                    </div>
                  </button>
                  {/* 展开详情面板 */}
                  {isOpen && (
                    <div style={{
                      position: "absolute", top: "calc(100% + 6px)",
                      left: i === 2 ? "auto" : 0,
                      right: i === 2 ? 0 : "auto",
                      width: 180, zIndex: 30,
                      ...glass(0.55, 20), borderRadius: 14,
                      padding: "12px 14px",
                      border: `1px solid ${_T.primary}28`,
                      animation: "fadeUp 0.22s cubic-bezier(.175,.885,.32,1.275) both",
                      boxShadow: `0 8px 32px ${_T.glassSH}, inset 0 1px 0 rgba(255,255,255,0.55)`,
                    }}>
                      <p style={{ fontSize: 11, fontWeight: 700, color: _T.primary, margin: "0 0 8px" }}>{stat.detail.title}</p>
                      {stat.detail.lines.map((line, li) => (
                        <p key={li} style={{
                          fontSize: 10, color: li === stat.detail.lines.length - 1 ? _T.primary : _T.textSub,
                          margin: "0 0 4px", lineHeight: 1.6,
                          fontStyle: line.startsWith("—") ? "italic" : "normal",
                          fontWeight: line.startsWith("—") ? 600 : 400,
                        }}>{line}</p>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        );
      })()}

      {/* 模式切换 — 液态玻璃按钮 */}
      <div style={{ display: "flex", gap: 6, marginBottom: 14, position: "relative", zIndex: 5 }}>
        {[{ id: "calendar", label: "日历" }, { id: "stats", label: "统计" }].map(m => (
          <button key={m.id} onClick={() => setViewMode(m.id)} style={{
            flex: 1, padding: "10px 0", borderRadius: 14, border: viewMode === m.id ? `1.5px solid ${_T.primary}30` : `1px solid rgba(255,255,255,${_T.dark ? 0.06 : 0.4})`, cursor: "pointer",
            background: viewMode === m.id
              ? (_T.dark ? `linear-gradient(145deg, rgba(255,255,255,0.08), rgba(255,255,255,0.03))` : `linear-gradient(145deg, rgba(255,255,255,0.9), rgba(255,255,255,0.6))`)
              : (_T.dark ? "rgba(255,255,255,0.03)" : "rgba(255,255,255,0.3)"),
            color: viewMode === m.id ? _T.primary : _T.textLight,
            fontSize: 12, fontWeight: 700, fontFamily: "inherit",
            boxShadow: viewMode === m.id ? `0 2px 12px rgba(0,0,0,${_T.dark ? 0.2 : 0.06}), inset 0 1px 0 rgba(255,255,255,${_T.dark ? 0.06 : 0.7})` : "none",
            transition: "all 0.3s ease",
            WebkitTapHighlightColor: "transparent",
          }}>{m.label}</button>
        ))}
      </div>

      {viewMode === "calendar" && (
        <>
          {/* 日历 — 液态玻璃容器 */}
          <div style={{ ...liquidGlassContainer, borderRadius: 22, padding: 1.5, marginBottom: 16, overflow: "visible" }}>
            <div style={{ ...liquidGlassInner, borderRadius: 21, padding: 12, position: "relative", overflow: "visible" }}>
              <div style={{ ...specularHL, borderRadius: "21px 21px 0 0" }} />
              <div style={{ position: "relative", zIndex: 4, display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 6, overflow: "visible" }}>
                {dayData.map((d, i) => {
                  const hasPractice = d.practiceCount > 0;
                  const isSelected = sel?.day === d.day;
                  const isPressed = pressedCell === i;
                  const hasWhisper = whisper.idx === i;
                  const isEmotion1 = d.emotion === "怀旧" || d.emotion === "平静" || d.emotion === "忧伤";
                  const gPair = d.filled ? (isEmotion1 ? _T.calGlass.light : _T.calGlass.active) : null;
                  const cellBg = d.filled
                    ? `linear-gradient(145deg, ${gPair[0]}cc, ${gPair[1]}aa)`
                    : (_T.dark ? "rgba(255,255,255,0.04)" : "rgba(255,255,255,0.45)");
                  const emotionColor = d.color || _T.primary;
                  const glowOff = `0 2px 10px ${_T.glassSH}, inset 0 1px 0 rgba(255,255,255,${_T.dark ? 0.1 : 0.5}), 0 0 0 0 ${emotionColor}00`;
                  const glowOn = `0 2px 10px ${_T.glassSH}, inset 0 1px 0 rgba(255,255,255,${_T.dark ? 0.1 : 0.5}), 0 0 12px 2px ${emotionColor}30`;
                  return (
                    <div key={i}
                      onClick={() => handleCellPress(i, d)}
                      style={{
                        aspectRatio: "1", borderRadius: 12, position: "relative",
                        background: cellBg,
                        display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
                        fontSize: 11, color: d.filled ? (_T.dark ? "#E0E0F0" : _T.text) : _T.textLight, fontWeight: 600,
                        cursor: "pointer",
                        border: isSelected ? `2px solid ${_T.primary}` : `1px solid rgba(255,255,255,${d.filled ? 0.35 : (_T.dark ? 0.04 : 0.3)})`,
                        "--cell-glow-off": glowOff,
                        "--cell-glow-on": glowOn,
                        animation: isPressed
                          ? "cellCollapse 0.5s cubic-bezier(.2,.8,.3,1) forwards"
                          : d.filled ? `cellBreathe ${3.5 + (i % 5) * 0.6}s ease-in-out ${(i % 7) * 0.3}s infinite` : undefined,
                        boxShadow: d.filled ? glowOff : `inset 0 1px 0 rgba(255,255,255,${_T.dark ? 0.04 : 0.5})`,
                        WebkitTapHighlightColor: "transparent",
                        overflow: "visible",
                      }}>
                      {/* Inner glow flash on press */}
                      {isPressed && d.filled && (
                        <div style={{
                          position: "absolute", inset: -2, borderRadius: 14,
                          background: `radial-gradient(circle, ${emotionColor}50 0%, ${emotionColor}15 50%, transparent 75%)`,
                          animation: "cellInnerGlow 0.6s ease-out forwards",
                          pointerEvents: "none", zIndex: 0,
                        }} />
                      )}
                      <span style={{ position: "relative", zIndex: 1 }}>{d.day}</span>
                      {d.filled && (
                        <div style={{ position: "absolute", bottom: 3, display: "flex", gap: 2, zIndex: 1 }}>
                          {hasPractice ? (
                            Array.from({ length: Math.min(d.practiceCount, 3) }).map((_, pi) => (
                              <div key={pi} style={{ width: 3, height: 3, borderRadius: "50%", background: _T.dark ? "rgba(255,255,255,0.7)" : `${_T.primary}`, opacity: 0.4 + pi * 0.3 }} />
                            ))
                          ) : (
                            <div style={{ width: 3, height: 3, borderRadius: "50%", background: _T.dark ? "rgba(255,255,255,0.2)" : `${_T.primary}30` }} />
                          )}
                        </div>
                      )}
                      {/* Whisper text bubble */}
                      {hasWhisper && (() => {
                        const col = i % 7;
                        const alignRight = col >= 5;
                        const alignLeft = col <= 1;
                        return (
                        <div style={{
                          position: "absolute", bottom: "calc(100% + 8px)",
                          ...(alignRight ? { right: -2 } : alignLeft ? { left: -2 } : { left: "50%", transform: "translateX(-50%)" }),
                          whiteSpace: "nowrap",
                          // 地雷系气泡：极薄白底 + 主色细描边 + 无圆角（方形更有日系贴纸感）
                          padding: "5px 10px 5px 8px",
                          borderRadius: "2px 10px 10px 10px",
                          background: _T.dark
                            ? `linear-gradient(135deg, rgba(30,28,40,0.92), rgba(40,36,55,0.88))`
                            : `linear-gradient(135deg, rgba(255,255,255,0.96), rgba(255,248,252,0.92))`,
                          backdropFilter: "blur(8px)",
                          WebkitBackdropFilter: "blur(8px)",
                          // 左上直角 = "撕下来的便利贴"感
                          border: `1px solid ${emotionColor}50`,
                          borderLeft: `2.5px solid ${emotionColor}AA`,
                          boxShadow: `2px 2px 0 ${emotionColor}22, 0 4px 12px rgba(0,0,0,0.06)`,
                          // 日语自言自语：字号偏小，字重轻，间距宽
                          fontSize: 10, fontWeight: 400,
                          color: _T.dark ? `${emotionColor}EE` : emotionColor,
                          letterSpacing: 1.2,
                          fontFamily: "'Shippori Mincho', serif",
                          lineHeight: 1.4,
                          animation: "whisperIn 2.4s ease-out forwards",
                          pointerEvents: "none",
                          zIndex: 99,
                          // 竖排感：文字不超过 10 个字，细而长
                          maxWidth: 120,
                          whiteSpace: "pre",
                        }}>
                          {whisper.text}
                        </div>
                        );
                      })()}
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          <p style={{ fontSize: 9, color: _T.textLight, margin: "0 0 14px", display: "flex", alignItems: "center", gap: 8, justifyContent: "center" }}>
            <span>色块 = 当日情绪</span><span>·</span><span>白点 = 练了几首</span><span>·</span><span>空格 = 休息日</span>
          </p>

          {/* 选中详情 — 液态玻璃 */}
          {sel && (
            <div style={{ ...liquidGlassContainer, borderRadius: 20, padding: 1.5, marginBottom: 14, animation: "fadeUp 0.2s ease both" }}>
              <div style={{ ...liquidGlassInner, borderRadius: 19, padding: 16, position: "relative" }}>
                <div style={{ ...specularHL, borderRadius: "19px 19px 0 0" }} />
                <div style={{ position: "relative", zIndex: 4 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                    <div>
                      <div style={{ fontSize: 15, fontWeight: 700, color: _T.text }}>3月{sel.day}日</div>
                      <div style={{ fontSize: 12, color: sel.color, fontWeight: 600, marginTop: 2 }}>{sel.word} · {sel.emotion}</div>
                    </div>
                    {sel.practiceCount > 0 && (
                      <div style={{ textAlign: "right" }}>
                        <span style={{ fontSize: 11, color: _T.textSub }}>练了 {sel.practiceCount} 首</span>
                        <p style={{ fontSize: 10, color: _T.textLight, margin: "2px 0 0" }}>约 {sel.practiceMinutes} 分钟</p>
                      </div>
                    )}
                  </div>
                  {sel.practiceCount === 0 && (
                    <p style={{ fontSize: 11, color: _T.textLight, margin: "8px 0 0", fontStyle: "italic" }}>这天没有练习，休息也是修行的一部分哦～</p>
                  )}
                </div>
              </div>
            </div>
          )}
        </>
      )}

      {viewMode === "stats" && (
        <>
          {/* 曲目练习量 — 液态玻璃 */}
          <div style={{ ...liquidGlassContainer, borderRadius: 22, padding: 1.5, marginBottom: 14 }}>
            <div style={{ ...liquidGlassInner, borderRadius: 21, padding: 16, position: "relative" }}>
              <div style={{ ...specularHL, borderRadius: "21px 21px 0 0" }} />
              <div style={{ position: "relative", zIndex: 4 }}>
                <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 12px", fontWeight: 600 }}>曲目练习量</p>
                {songFreq.map((s, i) => {
                  const maxCount = Math.max(...songFreq.map(x => x.count), 1);
                  const pct = (s.count / maxCount) * 100;
                  // find the live song id to cycle its status
                  const liveSong = stageSongs.find(song => song.title === s.title);
                  const STATUS_CYCLE_MAP = { new: "almost", almost: "smooth", smooth: "new" };
                  return (
                    <div key={i} style={{ marginBottom: 10 }}>
                      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                        <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                          <span style={{ fontSize: 13, fontWeight: 600, color: _T.text }}>{s.title}</span>
                          {liveSong && (
                            <StatusDot
                              status={liveSong.status}
                              onCycle={() => onCycleSongStatus?.(liveSong.id, STATUS_CYCLE_MAP[liveSong.status])}
                            />
                          )}
                        </div>
                        <span style={{ fontSize: 11, color: _T.textSub, fontWeight: 700 }}>{s.count}次</span>
                      </div>
                      <div style={{ height: 6, borderRadius: 99, background: _T.dark ? "rgba(255,255,255,0.06)" : "rgba(255,255,255,0.5)", overflow: "hidden", boxShadow: `inset 0 1px 2px rgba(0,0,0,${_T.dark ? 0.2 : 0.05})` }}>
                        <div style={{ height: "100%", borderRadius: 99, background: `linear-gradient(90deg, ${getSongStatusColor(liveSong?.status || s.status)}dd, ${getSongStatusColor(liveSong?.status || s.status)}77)`, width: `${pct}%`, transition: "width 0.5s ease, background 0.4s ease", boxShadow: `inset 0 1px 0 rgba(255,255,255,0.4)` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* 本周情绪×练习 — 液态玻璃 */}
          <div style={{ ...liquidGlassContainer, borderRadius: 22, padding: 1.5, marginBottom: 14 }}>
            <div style={{ ...liquidGlassInner, borderRadius: 21, padding: 16, position: "relative" }}>
              <div style={{ ...specularHL, borderRadius: "21px 21px 0 0" }} />
              <div style={{ position: "relative", zIndex: 4 }}>
                <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 12px", fontWeight: 600 }}>本周 情绪 × 练习量</p>
                <div style={{ display: "flex", alignItems: "flex-end", gap: 8, height: 100 }}>
                  {weekPractice.map((d, i) => (
                    <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 3 }}>
                      <div style={{
                        width: "100%", height: d.mins, borderRadius: 8, position: "relative", overflow: "hidden",
                        background: `linear-gradient(180deg, ${d.moodColor}dd, ${d.moodColor}77)`,
                        transition: "height 0.5s ease",
                        boxShadow: `0 2px 8px ${d.moodColor}25, inset 0 1px 0 rgba(255,255,255,0.4), inset 0 -1px 0 rgba(0,0,0,0.08)`
                      }}>
                        {/* Glass highlight on each bar */}
                        <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: "40%", background: "linear-gradient(180deg, rgba(255,255,255,0.3), transparent)", borderRadius: "8px 8px 0 0" }} />
                      </div>
                      <span style={{ fontSize: 10, color: _T.textLight, fontWeight: 600 }}>{d.label}</span>
                    </div>
                  ))}
                </div>
                <p style={{ fontSize: 9, color: _T.textLight, margin: "8px 0 0", textAlign: "center" }}>柱高 = 练习时长 · 颜色 = 当天情绪</p>
              </div>
            </div>
          </div>

          {/* Live冲刺 — 液态玻璃 */}
          <div style={{ ...liquidGlassContainer, borderRadius: 22, padding: 1.5, marginBottom: 14 }}>
            <div style={{ ...liquidGlassInner, borderRadius: 21, padding: 16, position: "relative" }}>
              <div style={{ ...specularHL, borderRadius: "21px 21px 0 0" }} />
              <div style={{ position: "relative", zIndex: 4 }}>
                <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 10px", fontWeight: 600 }}>Live前状态</p>
                <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                  <div style={{ flex: 1 }}>
                    <p style={{ fontSize: 11, color: _T.textSub, margin: "0 0 4px" }}>距离下场Live还有</p>
                    <p style={{ fontSize: 22, fontWeight: 800, color: _T.text, margin: 0 }}>{nextLive.daysLeft}<span style={{ fontSize: 11, fontWeight: 500 }}>天</span></p>
                  </div>
                  <div style={{ flex: 1 }}>
                    <p style={{ fontSize: 11, color: _T.textSub, margin: "0 0 4px" }}>本月Live相关曲目</p>
                    <div style={{ display: "flex", gap: 4 }}>
                      {stageSongs.filter(s => nextLive.setlist.some(sl => sl.song === s.title)).map((s, i) => {
                        const STATUS_CYCLE_MAP = { new: "almost", almost: "smooth", smooth: "new" };
                        return (
                          <StatusDot
                            key={i}
                            status={s.status}
                            onCycle={() => onCycleSongStatus?.(s.id, STATUS_CYCLE_MAP[s.status])}
                          />
                        );
                      })}
                    </div>
                    <p style={{ fontSize: 9, color: _T.textLight, margin: "4px 0 0" }}>
                      {stageSongs.filter(s => nextLive.setlist.some(sl => sl.song === s.title) && s.status === "smooth").length}/{nextLive.setlist.filter(s => s.song).length} 首已经稳了
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* 趋势提示 */}
          <div style={{ padding: "14px 16px", borderRadius: 14, background: `${_T.primary}06`, border: `1px solid rgba(255,255,255,${_T.dark ? 0.04 : 0.3})` }}>
            <p style={{ fontSize: 12, color: _T.textSub, margin: 0, lineHeight: 1.7 }}>
              {condition === "throat" ? "喉 — 不适。走位和表情为主。" :
               condition === "tired" ? "疲倦标记中。" :
               condition === "low" ? "低。" :
               filledDays >= 20 ? "高频练习中。" :
               filledDays >= 10 ? "节奏稳定。" :
               "练习记录较少。"}
            </p>
          </div>
        </>
      )}
    </div>
  );
}

// ─── StatusDot — iOS 系统风格状态切换点 ─────────────────────────────────────
// 点击：弹入缩放 + 颜色渐变 + 涟漪扩散（类 iOS 切换反馈）
function StatusDot({ status, onCycle }) {
  const [animKey, setAnimKey] = useState(0);
  const [ripple, setRipple] = useState(false);

  const handleClick = (e) => {
    e.stopPropagation(); // 不触发外层卡片选中
    setRipple(false);
    requestAnimationFrame(() => {
      setRipple(true);
      setAnimKey(k => k + 1);
      setTimeout(() => setRipple(false), 520);
    });
    onCycle?.();
  };

  const color = getSongStatusColor(status);
  const glow  = getSongStatusGlow(status);

  return (
    <button
      onClick={handleClick}
      style={{
        position: "relative",
        width: 24, height: 24,
        background: "none", border: "none", cursor: "pointer",
        display: "flex", alignItems: "center", justifyContent: "center",
        padding: 0, flexShrink: 0,
        // 外层撑大点击区域
      }}
    >
      {/* 涟漪圈 */}
      {ripple && (
        <span style={{
          position: "absolute",
          width: 24, height: 24,
          borderRadius: "50%",
          background: `${color}30`,
          animation: "statusRipple 0.52s cubic-bezier(0.2, 0.6, 0.4, 1) forwards",
          pointerEvents: "none",
        }} />
      )}
      {/* 状态点本体 */}
      <span
        key={animKey}   // key 变化触发重新渲染 → 重播动画
        style={{
          display: "block",
          width: 9, height: 9,
          borderRadius: "50%",
          background: color,
          boxShadow: glow,
          animation: animKey > 0
            ? "statusBounce 0.42s cubic-bezier(.175,.885,.32,1.275) both"
            : "none",
          transition: "background 0.28s ease, box-shadow 0.28s ease",
        }}
      />
    </button>
  );
}

// ===== DRAWERS & OVERLAYS =====
function SongDrawer({ songs, nextLive, onClose, onSelect, onUpdateNote, onUpdateCallGuide, onAddSong, onDeleteSong, onCycleSongStatus }) {
  const [selectedSongId, setSelectedSongId] = useState(songs[0]?.id || null);
  const selectedSong = songs.find(item => item.id === selectedSongId) || songs[0];
  const [draftNote, setDraftNote] = useState(selectedSong?.note || "");
  const [draftCall, setDraftCall] = useState(selectedSong?.callGuide || "");
  const [showCallEdit, setShowCallEdit] = useState(false);
  const [showAddSong, setShowAddSong] = useState(false);
  const [newSongTitle, setNewSongTitle] = useState("");
  const [confirmDelete, setConfirmDelete] = useState(null);

  useEffect(() => {
    setDraftNote(selectedSong?.note || "");
    setDraftCall(selectedSong?.callGuide || "");
    setShowCallEdit(false);
  }, [selectedSongId, selectedSong?.note, selectedSong?.callGuide]);

  const liveSongNames = nextLive.setlist.map(item => item.song).filter(Boolean);

  const handleAddSong = () => {
    if (!newSongTitle.trim()) return;
    const newSong = {
      id: Date.now(),
      title: newSongTitle.trim(),
      status: "new",
      note: "— 刚开始练",
      lastPractice: "还没练过",
      practiceCount: 0,
      retryCount: 0,
      passCount: 0,
      callGuide: "",
      callHints: [],
      mcKeywords: [],
      nextSongId: null,
    };
    onAddSong?.(newSong);
    setNewSongTitle("");
    setShowAddSong(false);
    setSelectedSongId(newSong.id);
  };

  const STATUS_CYCLE = { new: "almost", almost: "smooth", smooth: "new" };
  const STATUS_NEXT_LABEL = { new: "→ 未完成", almost: "→ 稳定", smooth: "→ 重置" };

  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 90, background: _T.dark ? "rgba(20,22,30,0.95)" : "rgba(255,255,255,0.93)", backdropFilter: "blur(30px)", animation: "slideUp 0.4s cubic-bezier(.175,.885,.32,1.275) both", overflowY: "auto" }}>
      <div style={{ padding: "60px 16px 100px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <h2 style={{ fontSize: 20, fontWeight: 800, color: _T.text, margin: 0, fontFamily: "'Shippori Mincho', serif" }}>曲目手帐</h2>
          <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer", color: _T.textLight, fontSize: 22, fontFamily: "inherit" }}>×</button>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "1fr", gap: 10, marginBottom: 16 }}>
          {songs.map(s => (
            <div key={s.id} style={{ position: "relative" }}>
              <button onClick={() => setSelectedSongId(s.id)} style={{ width: "100%", textAlign: "left", ...glass(0.4, 18), borderRadius: 16, padding: "14px 44px 14px 14px", display: "flex", justifyContent: "space-between", alignItems: "center", cursor: "pointer", border: selectedSongId === s.id ? `1px solid ${_T.primary}` : "1px solid transparent", background: selectedSongId === s.id ? `${_T.primary}10` : undefined, fontFamily: "inherit" }}>
                <div style={{ textAlign: "left" }}>
                  <div style={{ fontSize: 14, fontWeight: 700, color: _T.text }}>{s.title}</div>
                  <div style={{ fontSize: 11, color: _T.textLight, marginTop: 2 }}>{getSongStatusLabel(s.status)}</div>
                </div>
                <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                  {liveSongNames.includes(s.title) && <span style={{ fontSize: 10, padding: "3px 8px", borderRadius: 8, background: `${_T.primary}16`, color: _T.primary, fontWeight: 700, textShadow: _T.textGlow || 'none' }}>Live 相关</span>}
                  {/* iOS 风格状态点 — 独立可点击，带弹入 + 涟漪动效 */}
                  <StatusDot
                    status={s.status}
                    onCycle={() => onCycleSongStatus?.(s.id, STATUS_CYCLE[s.status])}
                  />
                </div>
              </button>
              {/* 删除按钮 */}
              {songs.length > 1 && (
                <button
                  onClick={() => setConfirmDelete(confirmDelete === s.id ? null : s.id)}
                  style={{ position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: _T.textLight, fontSize: 16, padding: "4px 6px", opacity: 0.5 }}
                >×</button>
              )}
              {confirmDelete === s.id && (
                <div style={{ ...glass(0.5, 14), borderRadius: 12, padding: "10px 14px", marginTop: 4, display: "flex", alignItems: "center", gap: 10, animation: "fadeUp 0.2s ease both" }}>
                  <span style={{ fontSize: 11, color: _T.text, flex: 1 }}>删除「{s.title}」？</span>
                  <button onClick={() => { onDeleteSong?.(s.id); setConfirmDelete(null); if (selectedSongId === s.id) setSelectedSongId(songs.find(x => x.id !== s.id)?.id); }} style={{ padding: "4px 10px", borderRadius: 8, border: "none", cursor: "pointer", background: "#F0826A20", color: "#F0826A", fontSize: 10, fontWeight: 700, fontFamily: "inherit" }}>确认删除</button>
                  <button onClick={() => setConfirmDelete(null)} style={{ padding: "4px 10px", borderRadius: 8, border: "none", cursor: "pointer", ...glass(0.3, 10), color: _T.textLight, fontSize: 10, fontFamily: "inherit" }}>取消</button>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* 添加新曲目 */}
        {!showAddSong ? (
          <button onClick={() => setShowAddSong(true)} style={{ width: "100%", padding: "13px 0", borderRadius: 16, border: `1px dashed ${_T.textLight}40`, cursor: "pointer", background: "transparent", color: _T.textLight, fontSize: 13, fontWeight: 600, fontFamily: "inherit", marginBottom: 16 }}>
            + 添加新曲目
          </button>
        ) : (
          <div style={{ ...glass(0.4, 18), borderRadius: 16, padding: 14, marginBottom: 16, animation: "fadeUp 0.2s ease both" }}>
            <input
              value={newSongTitle}
              onChange={e => setNewSongTitle(e.target.value)}
              onKeyDown={e => e.key === "Enter" && handleAddSong()}
              placeholder="曲目名称…"
              autoFocus
              style={{ width: "100%", padding: "10px 12px", borderRadius: 12, fontSize: 14, border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3), color: _T.text, outline: "none", fontFamily: "inherit", marginBottom: 10 }}
            />
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={handleAddSong} style={{ flex: 1, padding: "10px 0", borderRadius: 12, border: "none", cursor: "pointer", background: `linear-gradient(135deg, ${_T.primary}25, ${_T.primaryDeep}15)`, color: _T.primaryDeep, fontSize: 12, fontWeight: 700, fontFamily: "inherit" }}>添加</button>
              <button onClick={() => { setShowAddSong(false); setNewSongTitle(""); }} style={{ flex: 1, padding: "10px 0", borderRadius: 12, border: "none", cursor: "pointer", ...glass(0.3, 12), color: _T.textLight, fontSize: 12, fontFamily: "inherit" }}>取消</button>
            </div>
          </div>
        )}

        {selectedSong && (
          <div style={{ ...glass(0.42, 20), borderRadius: 18, padding: 18 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
              <h3 style={{ fontSize: 18, fontWeight: 800, color: _T.text, margin: 0, fontFamily: "'Shippori Mincho', serif" }}>{selectedSong.title}</h3>
              {/* 状态切换按钮 */}
              <button onClick={() => onCycleSongStatus?.(selectedSong.id, STATUS_CYCLE[selectedSong.status])} style={{
                padding: "5px 10px", borderRadius: 10, border: "none", cursor: "pointer",
                background: `${getSongStatusColor(selectedSong.status)}18`, color: getSongStatusColor(selectedSong.status),
                fontSize: 10, fontWeight: 700, fontFamily: "inherit"
              }}>{getSongStatusLabel(selectedSong.status)} {STATUS_NEXT_LABEL[selectedSong.status]}</button>
            </div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 12 }}>
              <span style={{ fontSize: 11, color: _T.textSub, padding: "4px 8px", borderRadius: 8, background: `${_T.primary}10` }}>最近练过 {selectedSong.practiceCount || 0} 次</span>
              <span style={{ fontSize: 11, color: _T.textSub, padding: "4px 8px", borderRadius: 8, background: `${_T.primary}10` }}>通过 {selectedSong.passCount || 0} / 重试 {selectedSong.retryCount || 0}</span>
            </div>

            {/* 应援call指南 */}
            <div style={{ marginBottom: 12 }}>
              <button onClick={() => setShowCallEdit(!showCallEdit)} style={{
                display: "flex", alignItems: "center", gap: 6, background: "none", border: "none",
                cursor: "pointer", fontFamily: "inherit", padding: "4px 0", marginBottom: 4
              }}>
                <Residue glyph="·" size={0.65} color={_T.textLight} />
                <span style={{ fontSize: 12, color: _T.text, fontWeight: 600 }}>应援 · Call指南</span>
                <span style={{ fontSize: 10, color: _T.textLight, transform: showCallEdit ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.3s" }}>▼</span>
              </button>
              {selectedSong.callGuide && !showCallEdit && (
                <p style={{ fontSize: 11, color: _T.textSub, margin: "0 0 0 20px", lineHeight: 1.6 }}>{selectedSong.callGuide}</p>
              )}
              {showCallEdit && (
                <div style={{ animation: "fadeUp 0.2s ease both" }}>
                  <textarea
                    value={draftCall}
                    onChange={e => setDraftCall(e.target.value)}
                    placeholder="副歌：嗨～嗨～（挥手）/ 间奏：名字call / 落副歌：轻声跟唱…"
                    style={{
                      width: "100%", minHeight: 60, resize: "none", borderRadius: 12,
                      border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.3),
                      padding: 10, outline: "none", color: _T.text, fontFamily: "inherit", fontSize: 12,
                      marginBottom: 6
                    }}
                  />
                  <button onClick={() => { onUpdateCallGuide?.(selectedSong.id, draftCall); setShowCallEdit(false); }} style={{
                    padding: "6px 14px", borderRadius: 10, border: "none", cursor: "pointer",
                    background: `${_T.primary}18`, color: _T.primary, fontSize: 10, fontWeight: 700, fontFamily: "inherit"
                  }}>保存Call指南</button>
                </div>
              )}
            </div>

            <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 8px" }}>备注</p>
            <textarea
              value={draftNote}
              onChange={e => setDraftNote(e.target.value)}
              placeholder="站位 / 转场 / MC接法 / 给自己的小memo～"
              style={{ width: "100%", minHeight: 110, resize: "none", borderRadius: 14, border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.38), padding: 12, outline: "none", color: _T.text, fontFamily: "inherit", fontSize: 13, marginBottom: 12 }}
            />
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={() => onSelect(selectedSong)} style={{ flex: 1, padding: "12px 0", borderRadius: 14, border: "none", cursor: "pointer", background: `linear-gradient(135deg, ${_T.primary}28, ${_T.primaryDeep}18)`, color: _T.primaryDeep, fontWeight: 700, fontFamily: "inherit" }}>开始练这首</button>
              <button onClick={() => onUpdateNote(selectedSong.id, draftNote)} style={{ flex: 1, padding: "12px 0", borderRadius: 14, border: "none", cursor: "pointer", ...glass(0.35, 16), color: _T.text, fontWeight: 700, fontFamily: "inherit" }}>保存备注</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const IDOL_REFLECTION_ITEMS = [
  { category: "站位走位", icon: "·", dimension: "sync", items: [
    { label: "站位移动", q: "移动的时候有没有犹豫？脚步记住了吗？", dim: "sync" },
    { label: "整体感觉", q: "移动中能意识到旁边的成员吗？整体画面看到了吗？", dim: "sync" },
  ]},
  { category: "表情管理", icon: "·", dimension: "stability", items: [
    { label: "笑容保持", q: "从头到尾笑容保持住了吗？间奏和MC衔接的时候呢？", dim: "stability" },
    { label: "眼神交流", q: "能看着镜头和观众的眼睛吗？还是一直低着头？", dim: "bodyCommit" },
  ]},
  { category: "MC · 煽动", icon: "·", dimension: "sync", items: [
    { label: "MC衔接", q: "MC的交接自然吗？有没有冷场或者撞词？", dim: "sync" },
    { label: "煽动气氛", q: "带动观众的时机对吗？音量够大吗？", dim: "bodyCommit" },
  ]},
  { category: "体力分配", icon: "…", dimension: "bodyCommit", items: [
    { label: "前半 vs 后半", q: "后半段体力有没有突然掉？从哪首歌开始变吃力了？", dim: "bodyCommit" },
    { label: "呼吸控制", q: "边唱边跳的时候，最喘的是哪里？", dim: "bodyCommit" },
  ]},
  { category: "衣装 · 道具", icon: "·", dimension: "stability", items: [
    { label: "快换流畅度", q: "换装来得及吗？最着急的是什么时候？", dim: "stability" },
    { label: "道具使用", q: "毛巾/扇子/荧光棒的切换有没有卡住？", dim: "stability" },
  ]},
  { category: "粉丝互动", icon: "○", dimension: "sync", items: [
    { label: "回应", q: "有和特定的观众对上眼吗？能自然地回应吗？", dim: "sync" },
    { label: "特典会", q: "特典会上聊得顺利吗？有没有紧张到僵住？笑容保持住了吗？", dim: "stability" },
  ]},
];

const DIM_LABEL = { stability: "安定性", sync: "同步感", bodyCommit: "身体投入" };
const DIM_ICON = { stability: "·", sync: "○", bodyCommit: "…" };

function IdolReflectionBlock({ lastLiveFeeling, idolChecks, onIdolCheck, reflectionScores, onUpdateScore }) {
  const [expandedCat, setExpandedCat] = useState(null);
  const [pulsingDim, setPulsingDim] = useState(null);
  const [noteKey, setNoteKey] = useState(null);
  const [noteText, setNoteText] = useState("");
  const [savedKeys, setSavedKeys] = useState({});   // key → flash 状态
  const [savedNote, setSavedNote] = useState({});   // key → saved note text

  const getScore = (key) => reflectionScores?.[key]?.score || 0;
  const getNote  = (key) => savedNote[key] || reflectionScores?.[key]?.note || "";

  const handleScore = (key, score, dim) => {
    // 如果已是这个分数则取消（toggle）
    const newScore = getScore(key) === score ? 0 : score;
    onUpdateScore?.(key, newScore, getNote(key));
    setPulsingDim(dim);
    // 闪烁保存确认
    setSavedKeys(prev => ({ ...prev, [key]: true }));
    setTimeout(() => setSavedKeys(prev => ({ ...prev, [key]: false })), 900);
    setTimeout(() => setPulsingDim(null), 800);
  };

  const handleNoteSave = (key) => {
    const note = noteText.trim();
    setSavedNote(prev => ({ ...prev, [key]: note }));
    onUpdateScore?.(key, getScore(key), note);
    setNoteKey(null);
    setNoteText("");
    setSavedKeys(prev => ({ ...prev, [key]: true }));
    setTimeout(() => setSavedKeys(prev => ({ ...prev, [key]: false })), 900);
  };

  const openNote = (key) => {
    setNoteKey(key);
    setNoteText(getNote(key));
  };

  const tiredTip = lastLiveFeeling === "tired"
    ? "这次体力上有点吃力呢。下次试着注意一下「体力分配」吧。"
    : null;

  const dimScores = {};
  let totalScore = 0;
  let totalItems = 0;
  IDOL_REFLECTION_ITEMS.forEach(cat => cat.items.forEach(item => {
    const key = `${cat.category}_${item.label}`;
    const s = getScore(key);
    if (s > 0) {
      dimScores[item.dim] = (dimScores[item.dim] || 0) + s;
      totalScore += s;
    }
    totalItems++;
  }));
  const maxScore = totalItems * 5;
  const scoredCount = Object.keys(reflectionScores || {}).filter(k => reflectionScores[k]?.score > 0).length;

  return (
    <div style={{ ...glass(0.36, 18), borderRadius: 16, padding: 16, marginBottom: 14 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
        <Residue glyph="·" size={0.8} color={_T.textLight} />
        <p style={{ fontSize: 12, color: _T.textLight, margin: 0, fontWeight: 600 }}>偶像复盘评分</p>
      </div>
      <p style={{ fontSize: 10, color: _T.textLight, margin: "0 0 10px", opacity: 0.7 }}>地偶现场自我检查（1～5分评分，点分数保存，再点取消）</p>

      <div style={{ display: "flex", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
        {["stability", "sync", "bodyCommit"].map(dim => {
          const isPulsing = pulsingDim === dim;
          const score = dimScores[dim] || 0;
          return (
            <div key={dim} style={{
              padding: "5px 10px", borderRadius: 10,
              background: score > 0 ? `${_T.primary}14` : inlineBg(0.2),
              display: "flex", alignItems: "center", gap: 5,
              transform: isPulsing ? "scale(1.12)" : "scale(1)",
              boxShadow: isPulsing ? `0 0 12px ${_T.primary}30` : "none",
              transition: "all 0.4s cubic-bezier(.175,.885,.32,1.275)"
            }}>
              <Residue glyph={DIM_ICON[dim]} size={0.7} color={score > 0 ? _T.primary : _T.textLight} />
              <span style={{ fontSize: 10, color: score > 0 ? _T.primary : _T.textLight, fontWeight: 700 }}>{DIM_LABEL[dim]}</span>
              {score > 0 && <span style={{ fontSize: 9, color: _T.primary, fontWeight: 800, marginLeft: 2 }}>avg {(score / Math.max(1, Object.keys(dimScores).length)).toFixed(1)}</span>}
            </div>
          );
        })}
      </div>

      {scoredCount > 0 && (
        <div style={{ marginBottom: 12 }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
            <span style={{ fontSize: 10, color: _T.textLight }}>复盘进度</span>
            <span style={{ fontSize: 10, color: _T.primary, fontWeight: 700, textShadow: _T.textGlow || 'none' }}>{scoredCount}/{totalItems}</span>
          </div>
          <div style={{ height: 4, borderRadius: 99, background: inlineBg(0.25), overflow: "hidden" }}>
            <div style={{ height: "100%", borderRadius: 99, background: `linear-gradient(90deg, ${_T.accent2}cc, ${_T.primary}cc)`, width: `${(scoredCount / totalItems) * 100}%`, transition: "width 0.5s cubic-bezier(.25,.1,.25,1)" }} />
          </div>
        </div>
      )}

      {tiredTip && (
        <div style={{ padding: "8px 12px", borderRadius: 10, background: `${_T.primary}08`, marginBottom: 12 }}>
          <p style={{ fontSize: 11, color: _T.primary, margin: 0, fontWeight: 600 }}>{tiredTip}</p>
        </div>
      )}
      {IDOL_REFLECTION_ITEMS.map((cat) => {
        const isOpen = expandedCat === cat.category;
        const catScored = cat.items.filter(item => getScore(`${cat.category}_${item.label}`) > 0).length;
        const catAvg = catScored > 0 ? (cat.items.reduce((a, item) => a + getScore(`${cat.category}_${item.label}`), 0) / cat.items.length).toFixed(1) : null;
        return (
          <div key={cat.category} style={{ marginBottom: 6 }}>
            <button
              onClick={() => setExpandedCat(isOpen ? null : cat.category)}
              style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 0", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit", borderBottom: `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}` }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <Residue glyph={cat.icon} size={0.9} color={_T.textSub} />
                <span style={{ fontSize: 13, color: _T.text, fontWeight: 600 }}>{cat.category}</span>
                {catAvg && <span style={{ fontSize: 9, padding: "2px 6px", borderRadius: 6, background: `${_T.primary}18`, color: _T.primary, fontWeight: 700, textShadow: _T.textGlow || 'none' }}>{catAvg}</span>}
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                <span style={{ fontSize: 9, color: _T.textLight, opacity: 0.6 }}>{DIM_LABEL[cat.dimension]}</span>
                <span style={{ fontSize: 11, color: _T.textLight, transform: isOpen ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.3s" }}>▼</span>
              </div>
            </button>
            {isOpen && (
              <div style={{ padding: "8px 0 4px 8px", animation: "fadeUp 0.25s ease both" }}>
                {cat.items.map((item) => {
                  const key = `${cat.category}_${item.label}`;
                  const currentScore = getScore(key);
                  const isSaved = savedKeys[key];
                  const existingNote = getNote(key);
                  const isEditingNote = noteKey === key;
                  return (
                    <div key={key} style={{ marginBottom: 14, paddingBottom: 10, borderBottom: `1px solid ${_T.dark ? "rgba(255,255,255,0.03)" : "rgba(0,0,0,0.03)"}` }}>
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 4 }}>
                        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                          <Residue glyph={DIM_ICON[item.dim]} size={0.45} color={_T.textLight} />
                          <p style={{ fontSize: 12, color: currentScore > 0 ? _T.primary : _T.text, margin: 0, fontWeight: 600, transition: "color 0.3s" }}>{item.label}</p>
                        </div>
                        {/* 已保存标记 */}
                        <span style={{
                          fontSize: 9, color: _T.primary, fontWeight: 700,
                          opacity: isSaved ? 1 : 0,
                          transform: isSaved ? "translateY(0) scale(1)" : "translateY(4px) scale(0.8)",
                          transition: "opacity 0.3s, transform 0.3s",
                        }}>已记录 ✓</span>
                      </div>
                      <p style={{ fontSize: 11, color: _T.textLight, margin: "0 0 8px", lineHeight: 1.6, paddingLeft: 16 }}>{item.q}</p>

                      {/* 评分按钮 */}
                      <div style={{ display: "flex", gap: 6, paddingLeft: 16, alignItems: "center" }}>
                        {[1, 2, 3, 4, 5].map(n => (
                          <button key={n} onClick={() => handleScore(key, n, item.dim)} style={{
                            width: 34, height: 30, borderRadius: 9, border: "none", cursor: "pointer",
                            background: n <= currentScore
                              ? `${_T.primary}${Math.round(20 + n * 8).toString(16)}`
                              : inlineBg(0.15),
                            color: n <= currentScore ? _T.primaryDeep : _T.textLight,
                            fontSize: 11, fontWeight: 700, fontFamily: "inherit",
                            transform: n === currentScore ? "scale(1.15) translateY(-1px)" : "scale(1)",
                            boxShadow: n === currentScore ? `0 2px 8px ${_T.primary}30` : "none",
                            transition: "all 0.22s cubic-bezier(.175,.885,.32,1.275)"
                          }}>{n}</button>
                        ))}
                        {/* 备注按钮 */}
                        <button onClick={() => openNote(key)} style={{
                          marginLeft: 6, padding: "4px 8px", borderRadius: 8, border: "none", cursor: "pointer",
                          background: existingNote ? `${_T.primary}18` : inlineBg(0.12),
                          color: existingNote ? _T.primary : _T.textLight, fontSize: 10, fontWeight: 600,
                          fontFamily: "inherit", transition: "all 0.2s"
                        }}>
                          {existingNote ? "📝" : "+ 备注"}
                        </button>
                      </div>

                      {/* 已有备注预览 */}
                      {existingNote && !isEditingNote && (
                        <p style={{ fontSize: 10, color: _T.textSub, margin: "6px 0 0 16px", fontStyle: "italic", lineHeight: 1.5, cursor: "pointer" }}
                          onClick={() => openNote(key)}>
                          「{existingNote}」
                        </p>
                      )}

                      {/* 备注输入框 */}
                      {isEditingNote && (
                        <div style={{ paddingLeft: 16, marginTop: 8, animation: "fadeUp 0.2s ease both" }}>
                          <textarea
                            value={noteText}
                            onChange={e => setNoteText(e.target.value)}
                            placeholder="写下记忆中的细节…"
                            rows={2}
                            autoFocus
                            style={{
                              width: "100%", padding: "8px 10px", borderRadius: 10, fontSize: 11,
                              border: `1px solid ${_T.glassBorder}`, background: inlineBg(0.25),
                              color: _T.text, outline: "none", fontFamily: "inherit",
                              resize: "none", lineHeight: 1.6, marginBottom: 6
                            }}
                          />
                          <div style={{ display: "flex", gap: 6 }}>
                            <button onClick={() => handleNoteSave(key)} style={{
                              flex: 1, padding: "7px 0", borderRadius: 10, border: "none", cursor: "pointer",
                              background: `linear-gradient(135deg, ${_T.primary}28, ${_T.primaryDeep}18)`,
                              color: _T.primaryDeep, fontSize: 11, fontWeight: 700, fontFamily: "inherit"
                            }}>保存备注</button>
                            <button onClick={() => { setNoteKey(null); setNoteText(""); }} style={{
                              padding: "7px 14px", borderRadius: 10, border: "none", cursor: "pointer",
                              ...glass(0.25, 10), color: _T.textLight, fontSize: 11, fontFamily: "inherit"
                            }}>取消</button>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

function ReflectionDrawer({ onClose, stageInsights, lastLiveFeeling, idolChecks, onIdolCheck, reflectionScores, onUpdateScore, performanceLogs }) {
  // Compute recent performance averages
  const recentLogs = (performanceLogs || []).slice(0, 10);
  const hasLogs = recentLogs.length > 0;
  const avgReaction = hasLogs ? (recentLogs.reduce((a, l) => a + (l.reactionScore || 0), 0) / recentLogs.length).toFixed(1) : null;
  const avgCall = hasLogs ? (recentLogs.reduce((a, l) => a + (l.callScore || 0), 0) / recentLogs.length).toFixed(1) : null;
  const avgSelf = hasLogs ? (recentLogs.reduce((a, l) => a + (l.selfScore || 0), 0) / recentLogs.length).toFixed(1) : null;

  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 90, background: _T.dark ? "rgba(20,22,30,0.95)" : "rgba(255,255,255,0.93)", backdropFilter: "blur(30px)", animation: "slideUp 0.4s cubic-bezier(.175,.885,.32,1.275) both", overflowY: "auto" }}>
      <div style={{ padding: "60px 16px 100px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24 }}>
          <h2 style={{ fontSize: 20, fontWeight: 800, color: _T.text, margin: 0, fontFamily: "'Shippori Mincho', serif" }}>复盘</h2>
          <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer", color: _T.textLight, fontSize: 22, fontFamily: "inherit" }}>×</button>
        </div>

        <div style={{ ...glass(0.48, 24), borderRadius: 20, padding: 22, marginBottom: 16, textAlign: "center" }}>
          <div style={{ marginBottom: 10, display: "flex", justifyContent: "center" }}><Residue glyph="·" size={1.6} color={_T.textLight} /></div>
          <h3 style={{ fontSize: 18, fontWeight: 800, color: _T.text, margin: "0 0 6px", fontFamily: "'Shippori Mincho', serif" }}>{stageInsights.recentChanges[0]}</h3>
          <p style={{ fontSize: 13, color: _T.textSub, margin: 0, lineHeight: 1.7 }}>你确实在往前走哦，这是毫无疑问的～</p>
        </div>

        {/* Performance Score Summary */}
        {hasLogs && (
          <div style={{ ...glass(0.4, 20), borderRadius: 18, padding: 18, marginBottom: 14 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
              <Residue glyph="✕" size={0.8} color={_T.primary} />
              <p style={{ fontSize: 12, color: _T.textLight, margin: 0, fontWeight: 600 }}>演出评分趋势（最近{recentLogs.length}首）</p>
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              {[
                { label: "客席反応", val: avgReaction, icon: "🎤" },
                { label: "call同步", val: avgCall, icon: "📣" },
                { label: "自分", val: avgSelf, icon: "💫" },
              ].map((item, i) => (
                <div key={i} style={{ flex: 1, textAlign: "center", padding: "10px 6px", borderRadius: 12, background: inlineBg(0.2) }}>
                  <span style={{ fontSize: 14 }}>{item.icon}</span>
                  <p style={{ fontSize: 18, fontWeight: 800, color: _T.text, margin: "4px 0 2px" }}>{item.val}</p>
                  <p style={{ fontSize: 9, color: _T.textLight, margin: 0 }}>{item.label}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        <div style={{ ...glass(0.38, 18), borderRadius: 16, padding: 16, marginBottom: 14 }}>
          <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 10px", fontWeight: 600 }}>最近的变化</p>
          {stageInsights.recentChanges.map((item, i) => (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 0", borderBottom: i < stageInsights.recentChanges.length - 1 ? `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}` : "none" }}>
              <span style={{ width: 22, display: "inline-flex", justifyContent: "center" }}><Residue glyph="·" size={0.8} color={_T.primary} /></span>
              <span style={{ fontSize: 13, color: _T.text, fontWeight: 500 }}>{item}</span>
            </div>
          ))}
        </div>

        <div style={{ ...glass(0.35, 18), borderRadius: 16, padding: 16, marginBottom: 14 }}>
          <p style={{ fontSize: 12, color: _T.textLight, margin: "0 0 10px", fontWeight: 600 }}>小小的里程碑</p>
          {stageInsights.milestones.map((item, i) => (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 0", borderBottom: i < stageInsights.milestones.length - 1 ? `1px solid ${_T.dark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)"}` : "none" }}>
              <Residue glyph={item.icon} size={1.2} color={_T.primary} />
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, color: _T.text, fontWeight: 700 }}>{item.label}</div>
                <div style={{ fontSize: 11, color: _T.textLight, marginTop: 2 }}>{item.date}</div>
              </div>
            </div>
          ))}
        </div>

        <IdolReflectionBlock lastLiveFeeling={lastLiveFeeling} idolChecks={idolChecks} onIdolCheck={onIdolCheck} reflectionScores={reflectionScores} onUpdateScore={onUpdateScore} />

        <div style={{ padding: "14px 16px", borderRadius: 14, background: `${_T.primary}06` }}>
          <p style={{ fontSize: 13, color: _T.textLight, margin: 0, lineHeight: 1.7, fontStyle: "italic" }}>
            {lastLiveFeeling === "tired" ? "这次有点累是正常的哦。先休息一下，之后再慢慢复盘吧～" : "不需要每次都完美的。能坚持练习这件事本身，就已经是很大的成长了"}
          </p>
        </div>
      </div>
    </div>
  );
}

